function closeNovaMovimentacaoModal(event) {
    if (event && event.target !== event.currentTarget && !event.target.closest('.modal-content')) return;
    const modal = document.getElementById('nova-mov-modal');
    if (modal) {
        modal.style.opacity = '0';
        setTimeout(() => modal.remove(), 200);
    }
}

function showAppModal({
    type = 'info',
    title = 'Aviso',
    message = '',
    detail = '',
    summary = '',
    confirmText = 'OK',
    cancelText = '',
    prompt = false,
    promptLabel = '',
    promptValue = '',
    promptPlaceholder = '',
    inputType = 'text',
    onConfirm = null,
    onCancel = null,
    closeOnBackdrop = true
} = {}) {
    return new Promise(resolve => {
        const existing = document.getElementById('app-confirm-modal');
        if (existing) existing.remove();
        document.getElementById('app-alert-modal')?.remove();

        const isConfirm = !!cancelText || !!prompt;
        const normalizedType = ['success', 'error', 'warning', 'confirm', 'info'].includes(type) ? type : 'info';
        const iconMap = {
            success: 'check_circle',
            error: 'error',
            warning: 'warning',
            confirm: 'help',
            info: 'info'
        };
        console.log('[APP_MODAL_ALERTS] exibindo modal', { type: normalizedType, title, isConfirm });
        const detailHtml = detail
            ? `<div class="app-confirm-detail">${String(detail).split('\n').filter(Boolean).map(line => `<span>${escapeKitAttribute(line)}</span>`).join('')}</div>`
            : '';
        const summaryHtml = summary
            ? `<div class="app-confirm-summary">${String(summary).split('\n').filter(Boolean).map(line => `<span>${escapeKitAttribute(line)}</span>`).join('')}</div>`
            : '';
        const promptHtml = prompt
            ? `<label class="app-confirm-prompt">
                    ${promptLabel ? `<span>${escapeKitAttribute(promptLabel)}</span>` : ''}
                    <input id="app-confirm-prompt-input" type="${escapeKitAttribute(inputType)}" value="${escapeKitAttribute(promptValue)}" placeholder="${escapeKitAttribute(promptPlaceholder)}" autocomplete="off">
               </label>`
            : '';

        const overlay = document.createElement('div');
        overlay.id = 'app-confirm-modal';
        overlay.className = `app-confirm-overlay app-standard-modal modal-${normalizedType}`;
        overlay.innerHTML = `
            <div class="app-confirm-dialog" role="dialog" aria-modal="true" aria-labelledby="app-confirm-title">
                <button type="button" class="app-modal-x" data-action="cancel" aria-label="Fechar">
                    <span class="material-symbols-rounded">close</span>
                </button>
                <div class="app-confirm-icon ${normalizedType}">
                    <span class="material-symbols-rounded">${iconMap[normalizedType]}</span>
                </div>
                <h3 id="app-confirm-title">${escapeKitAttribute(title)}</h3>
                ${message ? `<p>${escapeKitAttribute(message)}</p>` : ''}
                ${detailHtml}
                ${summaryHtml}
                ${promptHtml}
                <div class="app-confirm-actions ${isConfirm ? '' : 'app-alert-actions'}">
                    ${isConfirm ? `<button type="button" class="app-confirm-btn cancel" data-action="cancel">${escapeKitAttribute(cancelText)}</button>` : ''}
                    <button type="button" class="app-confirm-btn confirm ${normalizedType}" data-action="confirm">${escapeKitAttribute(confirmText)}</button>
                </div>
            </div>
        `;

        let settled = false;
        const close = async (confirmed) => {
            if (settled) return;
            settled = true;
            document.removeEventListener('keydown', onKeyDown);
            const promptValueResult = prompt ? (overlay.querySelector('#app-confirm-prompt-input')?.value || '') : '';
            try {
                if (confirmed && typeof onConfirm === 'function') await onConfirm(promptValueResult);
                if (!confirmed && typeof onCancel === 'function') await onCancel();
            } catch (error) {
                console.error('[APP_MODAL_ALERTS] erro no callback do modal', error);
            }
            overlay.classList.add('closing');
            setTimeout(() => overlay.remove(), 160);
            resolve(prompt ? (confirmed ? promptValueResult : null) : confirmed);
        };

        overlay.addEventListener('click', event => {
            const actionEl = event.target?.closest?.('[data-action]');
            const action = actionEl?.dataset?.action;
            if (event.target === overlay && closeOnBackdrop && !isConfirm) close(false);
            if (action === 'cancel') close(false);
            if (action === 'confirm') close(true);
        });

        const onKeyDown = event => {
            if (!document.body.contains(overlay)) {
                document.removeEventListener('keydown', onKeyDown);
                return;
            }
            if (event.key === 'Escape') close(false);
            if (event.key === 'Enter') close(true);
        };
        document.addEventListener('keydown', onKeyDown);

        document.body.appendChild(overlay);
        requestAnimationFrame(() => overlay.classList.add('open'));
        const promptInput = overlay.querySelector('#app-confirm-prompt-input');
        if (promptInput) setTimeout(() => promptInput.focus(), 30);
        else overlay.querySelector('[data-action="confirm"]')?.focus();
    });
}

function showAppConfirm({ title = 'Confirmar ação', message = '', detail = '', summary = '', confirmLabel = 'Confirmar', cancelLabel = 'Cancelar', danger = false } = {}) {
    return showAppModal({
        type: danger ? 'error' : 'confirm',
        title,
        message,
        detail,
        summary,
        confirmText: confirmLabel,
        cancelText: cancelLabel,
        closeOnBackdrop: false
    });
}

function showAppAlert({ title = 'Aviso', message = '', detail = '', summary = '', buttonLabel = 'OK', danger = false, icon = null } = {}) {
    const iconType = danger || icon === 'error' ? 'error' : (icon === 'check_circle' ? 'success' : (icon === 'warning' ? 'warning' : 'info'));
    playFeedbackSound(iconType === 'error' ? 'error' : 'warning');
    return showAppModal({
        type: iconType,
        title,
        message,
        detail,
        summary,
        confirmText: buttonLabel
    });
}

function showAppPrompt({ title = 'Informar dado', message = '', detail = '', label = '', defaultValue = '', placeholder = '', confirmLabel = 'Confirmar', cancelLabel = 'Cancelar', inputType = 'text' } = {}) {
    return showAppModal({
        type: 'confirm',
        title,
        message,
        detail,
        prompt: true,
        promptLabel: label,
        promptValue: defaultValue,
        promptPlaceholder: placeholder,
        inputType,
        confirmText: confirmLabel,
        cancelText: cancelLabel,
        closeOnBackdrop: false
    });
}

const SECURITY_DEVICE_ID_KEY = 'dy_security_device_id';
const SECURITY_PIN_SESSION_KEY = 'dy_security_pin_valid_until';
const SECURITY_PIN_TTL_MS = 5 * 60 * 1000;
let securityDeviceCheckTimer = null;

function getSecurityClient() {
    return window.supabaseClient || null;
}

function getSecurityTimestamp() {
    return new Date().toISOString();
}

function getOrCreateDeviceId() {
    let deviceId = localStorage.getItem(SECURITY_DEVICE_ID_KEY);
    if (!deviceId) {
        deviceId = crypto?.randomUUID ? crypto.randomUUID() : `device-${Date.now()}-${Math.random().toString(36).slice(2)}`;
        localStorage.setItem(SECURITY_DEVICE_ID_KEY, deviceId);
        console.log('[SECURITY] device_id gerado', deviceId);
    }
    return deviceId;
}

function getFriendlyDeviceName() {
    const ua = navigator.userAgent || '';
    const isMobile = /Android|iPhone|iPad|iPod/i.test(ua);
    const browser = /Edg/i.test(ua) ? 'Edge' : /Chrome/i.test(ua) ? 'Chrome' : /Firefox/i.test(ua) ? 'Firefox' : /Safari/i.test(ua) ? 'Safari' : 'Navegador';
    const type = isMobile ? 'Celular' : 'Desktop';
    const user = localStorage.getItem('currentUser');
    return user ? `${type} ${user}` : `${type} ${browser}`;
}

async function logSecurityEvent(acao, detalhes = '', deviceIdAfetado = null) {
    const client = getSecurityClient();
    if (!client) return;
    try {
        await client.from('logs_seguranca').insert([{
            acao,
            usuario_responsavel: localStorage.getItem('currentUser') || 'Sistema',
            device_id_afetado: deviceIdAfetado || getOrCreateDeviceId(),
            detalhes
        }]);
    } catch (error) {
        console.warn('[SEGURANCA] falha ao registrar log:', error);
    }
}

function logSecurityError(label, error, context = {}) {
    console.group(label);
    console.log('error:', error);
    console.log('code:', error?.code);
    console.log('message:', error?.message);
    console.log('details:', error?.details);
    console.log('hint:', error?.hint);
    if (Object.prototype.hasOwnProperty.call(context, 'payload')) console.log('payload:', context.payload);
    if (Object.prototype.hasOwnProperty.call(context, 'deviceId')) console.log('device_id:', context.deviceId);
    if (Object.prototype.hasOwnProperty.call(context, 'source')) console.log('source:', context.source);
    console.groupEnd();
}

function isMissingSecurityTableError(error) {
    const message = String(error?.message || '').toLowerCase();
    return error?.code === '42P01'
        || error?.code === '42883'
        || message.includes('does not exist')
        || message.includes('schema cache')
        || message.includes('could not find the function');
}

async function verifySecurityInstalled() {
    const client = getSecurityClient();
    if (!client) return { installed: false, configured: false, error: new Error('Supabase indisponível.') };

    const { data, error } = await client.rpc('pin_mestre_configurado');
    if (error) {
        logSecurityError('[SECURITY] erro ao verificar instalação', error);
        if (isMissingSecurityTableError(error)) {
            return { installed: false, configured: false, error };
        }
        return { installed: true, configured: false, error };
    }

    return { installed: true, configured: data === true, error: null };
}

async function ensureCurrentDeviceRegistered({
    userName = localStorage.getItem('currentUser'),
    userId = localStorage.getItem('currentUserId'),
    silent = true,
    source = 'app',
    logUpdate = true
} = {}) {
    const client = getSecurityClient();
    const deviceId = getOrCreateDeviceId();
    if (!client) return { allowed: true, deviceId, degraded: true };
    console.log('[SECURITY] device_id', deviceId);

    try {
        const securityStatus = await verifySecurityInstalled();
        if (!securityStatus.installed) {
            if (!silent) showToast('Tabelas de segurança ainda não aplicadas no Supabase.', 'warning');
            return { allowed: true, deviceId, degraded: true, error: securityStatus.error };
        }

        const { data: existingDevice, error: findError } = await client
            .from('dispositivos_autorizados')
            .select('*')
            .eq('device_id', deviceId)
            .maybeSingle();

        if (findError) {
            logSecurityError('[SECURITY] select dispositivo', findError, { deviceId, source });
            throw findError;
        }

        if (existingDevice && existingDevice.ativo === false) {
            console.log('[SECURITY] dispositivo encontrado', { deviceId, ativo: false, source });
            await logSecurityEvent('tentativa_dispositivo_bloqueado', 'Tentativa de acesso por dispositivo removido.', deviceId);
            renderBlockedDeviceScreen();
            return { allowed: false, deviceId, row: existingDevice };
        }

        if (existingDevice) {
            console.log('[SECURITY] dispositivo encontrado', { deviceId, source });
        }

        const payload = {
            usuario_id: userId || existingDevice?.usuario_id || null,
            nome_usuario: userName || existingDevice?.nome_usuario || 'Aguardando login',
            device_id: deviceId,
            nome_dispositivo: existingDevice?.nome_dispositivo || getFriendlyDeviceName(),
            ativo: true,
            ultimo_acesso: new Date().toISOString()
        };

        console.log('[SECURITY] payload dispositivo', payload);
        console.log('[SECURITY] supabase url', typeof SUPABASE_URL !== 'undefined' ? SUPABASE_URL : '(SUPABASE_URL indisponível)');

        const { data: savedDevice, error: upsertError } = await client
            .from('dispositivos_autorizados')
            .upsert(payload, { onConflict: 'device_id' })
            .select('*')
            .maybeSingle();

        if (upsertError) {
            logSecurityError('[SECURITY] insert/upsert dispositivo erro', upsertError, { payload, deviceId, source });
            throw upsertError;
        }

        console.log('[SECURITY] dispositivo salvo com sucesso', savedDevice || payload);
        if (existingDevice) {
            console.log('[SECURITY] ultimo_acesso atualizado', { deviceId, ultimo_acesso: payload.ultimo_acesso, source });
        } else {
            console.log('[SECURITY] dispositivo criado', { deviceId, source });
        }

        if (logUpdate) {
            await logSecurityEvent(
                existingDevice ? 'dispositivo_atualizado' : 'dispositivo_cadastrado',
                existingDevice
                    ? `Dispositivo atualizado via ${source}.`
                    : `Dispositivo cadastrado automaticamente: ${payload.nome_dispositivo}`,
                deviceId
            );
        }

        return { allowed: true, deviceId, row: savedDevice || payload };
    } catch (error) {
        logSecurityError('[SECURITY] update dispositivo', error, { deviceId, source });
        if (isMissingSecurityTableError(error)) {
            console.warn('[SEGURANCA] consulta de dispositivo falhou após RPC instalada; acesso liberado em modo compatibilidade.', error);
            return { allowed: true, deviceId, degraded: true, error };
        }
        console.warn('[SEGURANCA] falha na validação do dispositivo:', error);
        return { allowed: true, deviceId, degraded: true, error };
    }
}

async function ensureAuthorizedDevice(options = {}) {
    return ensureCurrentDeviceRegistered(options);
}

function renderBlockedDeviceScreen() {
    hideSplash();
    app.innerHTML = `
        <div class="security-blocked-screen">
            <div class="security-blocked-card">
                <span class="material-symbols-rounded">phonelink_lock</span>
                <h1>Dispositivo bloqueado</h1>
                <p>Este dispositivo foi removido por segurança.</p>
                <button type="button" onclick="location.reload()">Verificar novamente</button>
            </div>
        </div>
    `;
}

function startSecurityDeviceWatch() {
    if (securityDeviceCheckTimer) clearInterval(securityDeviceCheckTimer);
    securityDeviceCheckTimer = setInterval(() => {
        ensureCurrentDeviceRegistered({ silent: true, source: 'watch', logUpdate: false });
    }, 60000);
}

document.addEventListener('visibilitychange', () => {
    if (!document.hidden) ensureCurrentDeviceRegistered({ silent: true, source: 'visibility', logUpdate: false });
});

window.addEventListener('focus', () => ensureCurrentDeviceRegistered({ silent: true, source: 'focus', logUpdate: false }));

async function isMasterPinConfigured() {
    const status = await verifySecurityInstalled();
    if (!status.installed) throw status.error || new Error('Segurança não instalada.');
    if (status.error) throw status.error;
    return status.configured === true;
}

async function saveMasterPin(pin) {
    const client = getSecurityClient();
    if (!client) throw new Error('Supabase indisponível.');
    const cleanPin = String(pin || '').trim();
    if (cleanPin.length < 4) throw new Error('PIN deve ter pelo menos 4 dígitos.');
    const { error } = await client.rpc('set_pin_mestre', {
        p_pin: cleanPin,
        p_usuario: localStorage.getItem('currentUser') || 'Sistema'
    });
    if (error) throw error;
    sessionStorage.setItem(SECURITY_PIN_SESSION_KEY, String(Date.now() + SECURITY_PIN_TTL_MS));
    await logSecurityEvent('pin_mestre_alterado', 'PIN mestre atualizado.');
}

async function promptCreateMasterPin() {
    const pin = await showAppPrompt({
        title: 'Criar PIN mestre',
        message: 'Defina um PIN mestre para proteger configurações sensíveis.',
        detail: 'O PIN será salvo apenas como hash seguro. Não use PIN óbvio.',
        label: 'Novo PIN',
        inputType: 'password',
        confirmLabel: 'Salvar PIN',
        cancelLabel: 'Cancelar'
    });
    if (!pin) return false;
    const confirmPin = await showAppPrompt({
        title: 'Confirmar PIN mestre',
        message: 'Digite o PIN novamente para confirmar.',
        label: 'Confirmar PIN',
        inputType: 'password',
        confirmLabel: 'Confirmar',
        cancelLabel: 'Cancelar'
    });
    if (!confirmPin) return false;
    if (String(pin) !== String(confirmPin)) {
        await showAppAlert({ title: 'PIN não confere', message: 'Os PINs informados são diferentes.', icon: 'warning' });
        return false;
    }
    try {
        await saveMasterPin(pin);
        showToast('PIN mestre salvo.', 'success');
        return true;
    } catch (error) {
        await showAppAlert({ title: 'Erro ao salvar PIN', message: error.message || String(error), danger: true, icon: 'error' });
        return false;
    }
}

async function requireMasterPin(reason = 'ação sensível') {
    const deviceStatus = await ensureCurrentDeviceRegistered({ silent: true, source: 'acao_sensivel', logUpdate: false });
    if (deviceStatus.allowed === false) return false;

    const validUntil = Number(sessionStorage.getItem(SECURITY_PIN_SESSION_KEY) || 0);
    if (validUntil > Date.now()) return true;

    let pinConfigured = false;
    try {
        pinConfigured = await isMasterPinConfigured();
    } catch (error) {
        if (isMissingSecurityTableError(error)) {
            await showAppAlert({
                title: 'Segurança não configurada',
                message: 'Aplique a migration de segurança no Supabase antes de acessar esta área.',
                buttonLabel: 'OK',
                icon: 'warning'
            });
            return false;
        }
        await showAppAlert({ title: 'Erro de segurança', message: error.message || String(error), danger: true, icon: 'error' });
        return false;
    }

    if (!pinConfigured) {
        await showAppAlert({
            title: 'PIN mestre pendente',
            message: 'O valor atual de segurança é temporário e será substituído por um hash seguro.',
            detail: 'Crie um novo PIN mestre para continuar.',
            buttonLabel: 'Criar PIN',
            icon: 'warning'
        });
        return promptCreateMasterPin();
    }

    const pin = await showAppPrompt({
        title: 'PIN mestre',
        message: `Informe o PIN mestre para ${reason}.`,
        label: 'PIN',
        inputType: 'password',
        confirmLabel: 'Validar',
        cancelLabel: 'Cancelar'
    });
    if (!pin) return false;

    let valid = false;
    try {
        const { data, error } = await getSecurityClient().rpc('validar_pin_mestre', { p_pin: String(pin).trim() });
        if (error) throw error;
        valid = data === true;
    } catch (error) {
        await showAppAlert({ title: 'Erro ao validar PIN', message: error.message || String(error), danger: true, icon: 'error' });
        return false;
    }
    if (!valid) {
        await logSecurityEvent('pin_incorreto', `PIN incorreto ao tentar ${reason}.`);
        await showAppAlert({ title: 'PIN incorreto', message: 'O PIN informado não confere.', danger: true, icon: 'error' });
        return false;
    }

    sessionStorage.setItem(SECURITY_PIN_SESSION_KEY, String(Date.now() + SECURITY_PIN_TTL_MS));
    await logSecurityEvent('pin_validado', `PIN validado para ${reason}.`);
    return true;
}

let selectedTipoMovimentacao = null;
let selectedProductForMov = null;

function selectTipoMovimentacao(tipo, btn) {
    console.log(`[MOV] tipo selecionado: ${tipo}`);
    document.querySelectorAll('.tipo-mov-btn').forEach(b => {
        b.style.borderColor = 'rgba(255,255,255,0.1)';
        b.style.background = 'rgba(255,255,255,0.02)';
    });
    btn.style.borderColor = 'var(--primary)';
    btn.style.background = 'rgba(227,6,19,0.15)';
    
    selectedTipoMovimentacao = tipo;
    selectedProductForMov = null;
    
    renderMovimentacaoForm(tipo);
}

function renderMovimentacaoForm(tipo) {
    const container = document.getElementById('mov-form-container');
    const locals = STOCK_LOCALS;
    const origens = MOVIMENTACAO_ORIGINS;

    const getCommonFields = () => `
        <div class="input-group full-width">
            <label>Produto (EAN ou ID)</label>
            <input type="text" id="mov-search" class="input-field" placeholder="Bipe ou digite..." oninput="searchProductForMovInModal()">
            <div id="mov-search-results" style="margin-top: 8px; max-height: 120px; overflow-y: auto;"></div>
        </div>
        <div id="mov-selected-info" class="full-width" style="background: rgba(255,255,255,0.03); padding: 12px; border-radius: 12px; margin-bottom: 16px; border: 1px solid var(--primary); display: ${selectedProductForMov ? 'block' : 'none'};">
            <div style="font-weight: 700; color: white; font-size: 0.9rem;">${selectedProductForMov ? (selectedProductForMov.descricao_base || selectedProductForMov.nome || selectedProductForMov.col_b) : ''}</div>
            <div style="font-size: 0.7rem; color: var(--muted);">ID: ${selectedProductForMov ? (selectedProductForMov.id_interno || selectedProductForMov.col_a) : ''}</div>
        </div>
    `;

    const getOrigemField = () => `
        <div class="input-group">
            <label>Origem</label>
            <select id="mov-origem" class="input-field">
                ${origens.map(o => `<option value="${o.value}">${o.label}</option>`).join('')}
            </select>
        </div>
    `;

    const getDestinoField = () => `
        <div class="input-group">
            <label>Destino</label>
            <select id="mov-destino" class="input-field">
                ${locals.map(l => `<option value="${l}">${l}</option>`).join('')}
            </select>
        </div>
    `;

    const getLocalField = () => `
        <div class="input-group">
            <label>Local</label>
            <select id="mov-local" class="input-field">
                ${locals.map(l => `<option value="${l}">${l}</option>`).join('')}
            </select>
        </div>
    `;

    const getQuantidadeField = () => `
        <div class="input-group">
            <label>Quantidade</label>
            <input type="number" id="mov-qty" class="input-field" placeholder="0" min="1">
        </div>
    `;

    const getObservacaoField = () => `
        <div class="input-group full-width">
            <label>Observação</label>
            <input type="text" id="mov-obs" class="input-field" placeholder="Opcional">
        </div>
    `;

    const getAjusteTipoField = () => `
        <div class="input-group">
            <label>Tipo de Ajuste</label>
            <select id="mov-tipo-ajuste" class="input-field">
                <option value="positivo">Positivo (Entrada)</option>
                <option value="negativo">Negativo (Baixa)</option>
            </select>
        </div>
    `;

    const getMotivoField = () => `
        <div class="input-group full-width">
            <label>Motivo</label>
            <input type="text" id="mov-motivo" class="input-field" placeholder="Ex: Contagem inventário, ajuste sistema...">
        </div>
    `;

    let fieldsHTML = '';
    let submitLabel = '';
    let submitFunc = '';

    switch(tipo) {
        case 'ENTRADA':
            fieldsHTML = getCommonFields() + getDestinoField() + getOrigemField() + getQuantidadeField() + getObservacaoField();
            submitLabel = 'Registrar Entrada';
            submitFunc = "saveNovaMovimentacao('ENTRADA')";
            break;
        case 'SAIDA':
            fieldsHTML = getCommonFields() + getLocalField() + getOrigemField() + getQuantidadeField() + getObservacaoField();
            submitLabel = 'Registrar Saída';
            submitFunc = "saveNovaMovimentacao('SAIDA')";
            break;
        case 'TRANSFERENCIA':
            fieldsHTML = getCommonFields() + getLocalField().replace('id="mov-local"', 'id="mov-origem"') + getDestinoField() + getQuantidadeField() + getObservacaoField();
            submitLabel = 'Confirmar Transferência';
            submitFunc = "saveNovaMovimentacao('TRANSFERENCIA')";
            break;
        case 'AJUSTE':
            fieldsHTML = getCommonFields() + getLocalField() + getAjusteTipoField() + getQuantidadeField() + getMotivoField() + getObservacaoField();
            submitLabel = 'Registrar Ajuste';
            submitFunc = "saveNovaMovimentacao('AJUSTE')";
            break;
    }

    container.innerHTML = `
        <form onsubmit="event.preventDefault(); ${submitFunc}" style="display: flex; flex-direction: column; gap: 16px;">
            ${fieldsHTML}
            <div style="display: flex; gap: 12px; margin-top: 8px;">
                <button type="button" class="btn-action btn-secondary" style="flex: 1; justify-content: center;" onclick="closeNovaMovimentacaoModal()">Cancelar</button>
                <button type="submit" class="btn-action" style="flex: 2; justify-content: center;">${submitLabel}</button>
            </div>
        </form>
    `;
    console.log('[MOV] modal renderizado');
}


function searchProductForMovInModal() {
    const searchInput = document.getElementById('mov-search');
    const resultsDiv = document.getElementById('mov-search-results');

    if (!searchInput || !resultsDiv) return;

    const query = searchInput.value.toLowerCase();
    if (query.length < 2) {
        resultsDiv.innerHTML = '';
        return;
    }

    const results = (appData.products || []).filter(p =>
        (p.descricao_base || '').toLowerCase().includes(query) ||
        (p.ean || '').toString().toLowerCase().includes(query) ||
        (p.id_interno || '').toString().toLowerCase().includes(query)
    ).slice(0, 5);


    console.log(`[MOV] busca modal: "${query}" -> ${results.length} resultados`);

    resultsDiv.innerHTML = results.map(p => `
        <div style="padding: 10px; background: rgba(255,255,255,0.02); border-bottom: 1px solid rgba(255,255,255,0.05); cursor: pointer;" onclick="selectProductForMovInModal('${p.ean || p.id_interno}')">
            <div style="font-weight: 700; font-size: 0.8rem; color: white;">${p.descricao_base || p.nome}</div>
            <div style="font-size: 0.65rem; color: var(--muted);">SKU: ${p.id_interno || p.id}</div>
        </div>
    `).join('');
}


function selectProductForMovInModal(id) {
    console.log('[MOV] produto selecionado - ID:', id);
    selectedProductForMov = (appData.products || []).find(p => p.ean == id || p.id_interno == id);
    console.log('[MOV] selectedProduct atual:', selectedProductForMov);
    
    if (!selectedProductForMov) return;

    document.getElementById('mov-search').value = selectedProductForMov.descricao_base || selectedProductForMov.nome || '';
    document.getElementById('mov-search-results').innerHTML = '';

    const infoDiv = document.getElementById('mov-selected-info');
    if (infoDiv) {
        infoDiv.style.display = 'block';
        infoDiv.innerHTML = `
            <div style="font-weight: 700; color: white; font-size: 0.9rem;">${selectedProductForMov.descricao_base || selectedProductForMov.nome}</div>
            <div style="font-size: 0.7rem; color: var(--muted);">ID: ${selectedProductForMov.id_interno || selectedProductForMov.id}</div>
        `;
    }
    
    console.log('[MOV] produto vinculado ao state');
}

async function saveNovaMovimentacao(tipo) {
    console.log('[MOV] salvar clicado - tipo:', tipo);
    
    if (isFinalizing) {
        console.log('[MOV] Bloqueado: isFinalizing=true');
        return;
    }
    isFinalizing = true;

    // ==========================================
    // PASSO 1: LOCALIZAR E VALIDAR O PRODUTO
    // ==========================================
    console.log('========== VALIDACAO DETALHADA ==========');
    
    // Primeiro: verificar se produtos estão carregados no appData
    const produtosDisponiveis = appData.products || [];
    console.log('[MOV] produtos carregados no appData:', produtosDisponiveis.length);
    
    // Segundo: tentar encontrar o produto no state
    const searchInput = document.getElementById('mov-search');
    const inputValue = searchInput?.value?.trim() || '';
    console.log('[MOV] valor do input produto:', inputValue);
    console.log('[MOV] selectedProductForMov do state:', selectedProductForMov);
    
    // Terceiro: se não tem produto no state mas tem texto, buscar
    if (!selectedProductForMov && inputValue) {
        console.log('[MOV] trying to find product by text in appData...');
        
        // Buscar em appData.products
        const produtoEncontrado = produtosDisponiveis.find(p => {
            const idInterno = p.id_interno || p.col_a || '';
            const ean = p.ean || '';
            return idInterno.toString().trim() === inputValue || 
                   idInterno.toString().includes(inputValue) ||
                   ean.toString().trim() === inputValue;
        });
        
        if (produtoEncontrado) {
            selectedProductForMov = produtoEncontrado;
            console.log('[MOV] produto encontrado em appData.products:', selectedProductForMov.id_interno || selectedProductForMov.col_a);
        } else {
            // Se não achou em appData, tentar DataClient
            console.log('[MOV] não achou em appData, tentando DataClient...');
            try {
                const data = await DataClient.loadModule('produtos', false);
                if (data && data.products && data.products.length > 0) {
                    appData.products = data.products;
                    const produtoDataClient = data.products.find(p => {
                        const idInterno = p.id_interno || p.col_a || '';
                        return idInterno.toString().trim() === inputValue || 
                               idInterno.toString().includes(inputValue);
                    });
                    if (produtoDataClient) {
                        selectedProductForMov = produtoDataClient;
                        console.log('[MOV] produto encontrado via DataClient:', selectedProductForMov.id_interno || selectedProductForMov.col_a);
                    }
                }
            } catch (e) {
                console.log('[MOV] erro ao carregar produtos via DataClient:', e);
            }
        }
    }
    
    // Log final do produto
    console.log('[MOV] produto final para salvar:', selectedProductForMov ? (selectedProductForMov.id_interno || selectedProductForMov.col_a) : 'NULO');
    
    // ==========================================
    // PASSO 2: VALIDAR PRODUTO
    // ==========================================
    if (!selectedProductForMov) {
        console.log('[MOV] ERRO: produto NAO encontrado');
        console.log('[MOV] razao: selectedProductForMov é null');
        showToast("Produto não encontrado. Selecione da lista ou digite ID correto.");
        isFinalizing = false;
        console.log('=========================================');
        return;
    }
    console.log('[MOV] produto OK:', selectedProductForMov.id_interno || selectedProductForMov.col_a);

    // ==========================================
    // PASSO 3: LOCALIZAR E VALIDAR QUANTIDADE
    // ==========================================
    const qtyInput = document.getElementById('mov-qty');
    const qtyRaw = qtyInput?.value;
    console.log('[MOV] elemento quantidade encontrado:', qtyInput ? 'SIM' : 'NAO');
    console.log('[MOV] valor bruto quantidade:', qtyRaw);
    
    if (!qtyInput) {
        console.log('[MOV] ERRO: campo quantidade NAO encontrado no DOM');
        showToast("Erro: campo de quantidade não encontrado.");
        isFinalizing = false;
        console.log('=========================================');
        return;
    }

    const qty = parseFloat(qtyRaw);
    console.log('[MOV] quantidade parseada:', qty, 'isNaN:', isNaN(qty));

    if (isNaN(qty) || qty <= 0) {
        console.log('[MOV] ERRO: quantidade invalida');
        console.log('[MOV] razao: qty <= 0 ou isNaN');
        showToast("Quantidade inválida. Digite um número maior que 0.");
        isFinalizing = false;
        console.log('=========================================');
        return;
    }
    console.log('[MOV] quantidade OK:', qty);
    
    console.log('========== FIM VALIDACAO OK ==========');

    // ==========================================
    // PASSO 4: MONTAR PAYLOAD
    // ==========================================
    const obsInput = document.getElementById('mov-obs');
    const origemInput = document.getElementById('mov-origem');
    const destinoInput = document.getElementById('mov-destino');
    const localInput = document.getElementById('mov-local');
    const tipoAjusteInput = document.getElementById('mov-tipo-ajuste');
    const motivoInput = document.getElementById('mov-motivo');

    let localOrigem = '';
    let localDestino = '';
    let origem = 'MANUAL';
    let observacao = obsInput?.value?.trim() || '';

    if (tipo === 'ENTRADA') {
        localDestino = destinoInput?.value || '';
        origem = origemInput?.value || 'MANUAL';
    } else if (tipo === 'SAIDA') {
        localOrigem = localInput?.value || '';
        origem = origemInput?.value || 'MANUAL';
    } else if (tipo === 'TRANSFERENCIA') {
        localOrigem = document.getElementById('mov-origem')?.value || '';
        localDestino = destinoInput?.value || '';
    } else if (tipo === 'AJUSTE') {
        localOrigem = localInput?.value || '';
        const ajusteTipo = tipoAjusteInput?.value || 'positivo';
        const motivo = motivoInput?.value?.trim() || '';
        observacao = motivo ? `Ajuste ${ajusteTipo}: ${motivo}` : `Ajuste ${ajusteTipo}`;
        if (obsInput?.value?.trim()) {
            observacao += ' - ' + obsInput.value.trim();
        }
    }

    const movData = {
        tipo: tipo === 'AJUSTE' ? ((tipoAjusteInput?.value || 'positivo') === 'positivo' ? 'AJUSTE_POSITIVO' : 'AJUSTE_NEGATIVO') : tipo,
        id_interno: selectedProductForMov.id_interno || selectedProductForMov.col_a,
        local_origem: localOrigem,
        local_destino: localDestino,
        quantidade: qty,
        usuario: localStorage.getItem('currentUser'),
        origem: origem,
        observacao: observacao
    };

    console.log('[MOV] payload enviado:', JSON.stringify(movData, null, 2));

    showToast("Processando...");

    try {
        console.log('[MOV] Tentando insert em movimentos...');
        const savedMov = await DataClient.saveMovimentoSupabase(movData);
        
        if (!savedMov) {
            console.log('[MOV] ERRO: insert movimentos retornou null');
            showToast("Erro ao gravar movimento.");
            isFinalizing = false;
            return;
        }
        
        console.log('[MOV] insert movimentos sucesso:', savedMov);

        let stockSuccess = false;
        const idInterno = movData.id_interno;

        console.log(`[MOV] Atualizando estoque: tipo=${tipo} localOrigem=${localOrigem} localDestino=${localDestino}`);
        
        if (tipo === 'ENTRADA') {
            stockSuccess = await DataClient.updateEstoqueSupabase(idInterno, movData.local_destino, 'soma', movData.quantidade);
        } else if (tipo === 'SAIDA') {
            stockSuccess = await DataClient.updateEstoqueSupabase(idInterno, movData.local_origem, 'subtrai', movData.quantidade);
        } else if (tipo === 'TRANSFERENCIA') {
            const outOk = await DataClient.updateEstoqueSupabase(idInterno, movData.local_origem, 'subtrai', movData.quantidade);
            const inOk = await DataClient.updateEstoqueSupabase(idInterno, movData.local_destino, 'soma', movData.quantidade);
            stockSuccess = outOk && inOk;
        } else if (tipo === 'AJUSTE') {
            const ajusteTipo = tipoAjusteInput?.value || 'positivo';
            const operacao = ajusteTipo === 'positivo' ? 'soma' : 'subtrai';
            stockSuccess = await DataClient.updateEstoqueSupabase(idInterno, movData.local_origem, operacao, movData.quantidade);
        }

        console.log('[MOV] update estoque resultado:', stockSuccess);

        if (stockSuccess) {
            if (tipo === 'SAIDA') {
                await aplicarBaixaFIFOSeSaida(savedMov, idInterno, movData.quantidade, movData.local_origem);
            }
            console.log('[MOV] fluxo concluído com sucesso');
            console.log('[MOV] resposta de sucesso');
            showToast("Movimentação registrada com sucesso!");
            
            if (!appData.movimentacoes) appData.movimentacoes = [];
            appData.movimentacoes.unshift({
                ...savedMov,
                data: formatDateTimeBR(savedMov.data_hora)
            });

            DataClient.invalidateCache('produtos');
            
            console.log('[MOV] modal fechado após sucesso');
            closeNovaMovimentacaoModal();
            
            // Pequeno delay para garantir que toast apareça antes de renderizar nova tela
            setTimeout(() => {
                renderMovimentacoes();
                console.log('[MOV] mensagem exibida - tela atualizada');
            }, 300);
        } else {
            console.log('[MOV] ERRO: movimento salvo mas estoque não atualizado');
            console.log('[MOV] resposta de erro');
            showToast("Erro: Movimento salvo, mas estoque não atualizado.");
            console.log('[MOV] mensagem exibida');
        }
    } catch (e) {
        console.error('[MOV] ERRO fatal:', e);
        showToast("Erro fatal no processamento: " + e.message);
    } finally {
        isFinalizing = false;
    }
}

