// Variável global para armazenar o contexto da sessão antes de ser persistida
let currentPickingContext = null;
let lastScannedPickItemKey = null;
let expandedPickItemKey = null;
let pickRemovalModeActive = false;
let lastPickScanAction = 'add';
let pickScanHistory = [];
let scanCenterToastTimeout = null;
let scanSuccessGlowTimeout = null;
const PICK_STATUS_DRAFT = 'em_separacao';
const PICK_STATUS_READY_FOR_PACK = 'aberta';
const PICK_STATUS_FINISHED = 'finalizada';
const PICK_FAST_OBSERVATION = 'SAIDA_RAPIDA AUTOMATICA';
const PICK_MANUAL_OBSERVATION = 'SEPARACAO MANUAL';
const PICK_PACKAGE_TOTALS_STORAGE_KEY = 'dyPickPackageTotalsBySession';
const PICK_CURRENT_DRAFT_STORAGE_KEY = 'draft_pick_session';
const PICK_DRAFT_SESSIONS_STORAGE_KEY = 'draft_pick_sessions';

function isPickingFastModeSource(source = {}) {
    if (!source || typeof source !== 'object') return false;
    const observation = String(source.observacao || source.pickingData?.observacao || '').toUpperCase();
    return source.isFastMode === true
        || source.fastMode === true
        || source.modo_rapido === true
        || source.pickingData?.isFastMode === true
        || source.pickingData?.modo_rapido === true
        || observation.includes('SAIDA_RAPIDA')
        || observation.includes('MODO RAPIDO')
        || observation.includes('MODO_RAPIDO');
}

function isFastPickingPayload(payload = {}) {
    return isPickingFastModeSource(payload)
        || isPickingFastModeSource(payload.session)
        || isPickingFastModeSource(payload.pickingData)
        || payload.modo_rapido === true
        || payload.isFastMode === true;
}

function getConferenceSessionId(conf = {}) {
    return String(conf.separacao_id || conf.codigo_separacao || conf.pickingData?.separacao_id || '').trim();
}

function isPendingConferenceRow(conf = {}) {
    const status = String(conf.status || '').trim().toLowerCase();
    return !['conferido', 'finalizada', 'finalizado', 'cancelada', 'cancelado'].includes(status);
}

function hasPendingConferenceForSession(sessionOrId) {
    const sessionId = typeof sessionOrId === 'object'
        ? String(getPackSeparationSessionId(sessionOrId) || '').trim()
        : String(sessionOrId || '').trim();
    if (!sessionId) return false;
    return (appData.conferencia || []).some(conf => {
        const confSessionId = getConferenceSessionId(conf);
        return confSessionId === sessionId && isPendingConferenceRow(conf);
    });
}

function isSeparationPendingConferenceSession(session = {}) {
    const status = String(session.status || '').toLowerCase();
    const isReadyStatus = status === 'aberta' || status === 'pendente' || status === 'pronta_conferencia';
    return isReadyStatus && !isPickingFastModeSource(session) && hasPendingConferenceForSession(session);
}

function getActivePickingFastMode(draft = null) {
    return isPickingFastModeSource(currentPickingContext)
        || isPickingFastModeSource(draft)
        || isPickingFastModeSource(currentPickSession)
        || isPickingFastModeSource(currentPickSession?.pickingData);
}

function normalizePickPackageCount(value) {
    const count = Math.floor(Number(value || 0));
    return Number.isFinite(count) ? Math.max(0, count) : 0;
}

function getPickPackageCountFrom(source = {}) {
    if (!source || typeof source !== 'object') return 0;
    return normalizePickPackageCount(
        source.total_pacotes_montados
        ?? source.totalPacotesMontados
        ?? source.total_pacotes
        ?? source.qtd_pacotes
        ?? source.pacotes
        ?? source.volumes
        ?? source.packageCount
        ?? source.pacotesMontados
        ?? source.packagesMounted
        ?? 0
    );
}

function getPickPackageTotalsCache() {
    try {
        const parsed = JSON.parse(localStorage.getItem(PICK_PACKAGE_TOTALS_STORAGE_KEY) || '{}');
        return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : {};
    } catch (error) {
        localStorage.removeItem(PICK_PACKAGE_TOTALS_STORAGE_KEY);
        return {};
    }
}

function rememberPickPackageTotal(sessionId, source = {}) {
    const targetSessionId = String(sessionId || '').trim();
    if (!targetSessionId) return;
    const count = getPickPackageCountFrom(source);
    const cache = getPickPackageTotalsCache();
    cache[targetSessionId] = {
        total_pacotes_montados: count,
        atualizado_em: getDataHoraBrasil()
    };
    localStorage.setItem(PICK_PACKAGE_TOTALS_STORAGE_KEY, JSON.stringify(cache));
}

function hasPickPackageCount(source = {}) {
    if (!source || typeof source !== 'object') return false;
    return source.total_pacotes_montados !== undefined
        || source.totalPacotesMontados !== undefined
        || source.total_pacotes !== undefined
        || source.qtd_pacotes !== undefined
        || source.pacotes !== undefined
        || source.volumes !== undefined
        || source.packageCount !== undefined
        || source.pacotesMontados !== undefined
        || source.packagesMounted !== undefined;
}

function pickContextMatches(source = {}, sessionId = '', channelId = '', channelLabel = '') {
    if (!source || typeof source !== 'object') return false;
    const sourceSessionId = String(
        source.sessionId
        || source.separacao_id
        || source.pickingData?.separacao_id
        || source.pickingData?.sessionId
        || ''
    );
    const targetSessionId = String(sessionId || currentPickingContext?.sessionId || '').trim();
    if (targetSessionId) return sourceSessionId === targetSessionId;

    const sourceChannelId = String(source.channelId || source.canal_id || source.pickingData?.channelId || source.pickingData?.canal_id || '').trim();
    const targetChannelId = String(channelId || currentPickingContext?.channelId || '').trim();
    if (sourceChannelId && targetChannelId) return sourceChannelId === targetChannelId;

    const sourceChannel = normalizeOperationalLabel(source.channelLabel || source.canal_nome || source.canal || source.pickingData?.channelLabel || source.pickingData?.canal_nome || '');
    const targetChannel = normalizeOperationalLabel(channelLabel || currentPickingContext?.channelLabel || '');
    return Boolean(sourceChannel && targetChannel && sourceChannel === targetChannel);
}

function getScopedDraftPickSession(sessionId = '', channelId = '', channelLabel = '') {
    const targetSessionId = String(sessionId || currentPickingContext?.sessionId || '').trim();
    const localDraft = targetSessionId ? getLocalDraftPickSession(targetSessionId) : null;
    if (pickContextMatches(localDraft, sessionId, channelId, channelLabel)) return localDraft;
    const draft = getDraftPickSession();
    return pickContextMatches(draft, sessionId, channelId, channelLabel) ? draft : null;
}

function getCurrentPickPackageCount(sessionId = '', channelId = '', channelLabel = '') {
    const sources = [
        currentPickingContext,
        getScopedDraftPickSession(sessionId, channelId, channelLabel),
        currentPickSession?.pickingData,
        currentPickSession
    ];
    const targetSessionId = sessionId || currentPickingContext?.sessionId || currentPickSession?.pickingData?.separacao_id || '';
    const targetChannelId = channelId || currentPickingContext?.channelId || '';
    const targetChannelLabel = channelLabel || currentPickingContext?.channelLabel || '';
    for (const source of sources) {
        if (hasPickPackageCount(source) && pickContextMatches(source, targetSessionId, targetChannelId, targetChannelLabel)) {
            return getPickPackageCountFrom(source);
        }
    }
    return 0;
}

function getPickItemsTotal(items = currentSessionItems) {
    return (items || []).reduce((total, item) => total + (Number(item.qty || item.qtd_separada || item.quantidade || 0) || 0), 0);
}

function countDifferentPickProducts(items = currentSessionItems) {
    const uniqueProducts = new Set((items || [])
        .map(item => getPickingProductId(item) || normalizePickCode(item?.ean || item?.codigo || item?.descricao || ''))
        .filter(Boolean));
    return uniqueProducts.size || (items || []).length;
}

function getPickingOperationalStats(items = currentSessionItems) {
    const totalProdutosSeparados = countDifferentPickProducts(items);
    const totalItensSeparados = getPickItemsTotal(items);
    const totalPacotesMontados = getCurrentPickPackageCount();
    return {
        total_produtos_separados: totalProdutosSeparados,
        total_itens_separados: totalItensSeparados,
        total_pacotes_montados: totalPacotesMontados,
        media_itens_por_pacote: totalPacotesMontados > 0 ? totalItensSeparados / totalPacotesMontados : 0,
        media_produtos_por_pacote: totalPacotesMontados > 0 ? totalItensSeparados / totalPacotesMontados : 0
    };
}

function formatPickPackageAverage(value) {
    const numberValue = Number(value || 0);
    if (!Number.isFinite(numberValue) || numberValue <= 0) return '0';
    return numberValue.toLocaleString('pt-BR', { minimumFractionDigits: 0, maximumFractionDigits: 2 });
}

function syncPickPackageCount(count, persist = true) {
    const safeCount = normalizePickPackageCount(count);
    if (currentPickingContext) {
        currentPickingContext.total_pacotes_montados = safeCount;
        currentPickingContext.totalPacotesMontados = safeCount;
    }
    if (currentPickSession) {
        currentPickSession.total_pacotes_montados = safeCount;
        currentPickSession.totalPacotesMontados = safeCount;
        if (currentPickSession.pickingData) {
            currentPickSession.pickingData.total_pacotes_montados = safeCount;
            currentPickSession.pickingData.totalPacotesMontados = safeCount;
        }
    }

    const packagesEl = document.getElementById('pick-summary-packages');
    if (packagesEl) {
        if (packagesEl.matches('input')) {
            if (packagesEl.value !== String(safeCount)) packagesEl.value = String(safeCount);
        } else {
            packagesEl.textContent = String(safeCount);
        }
    }

    if (persist) {
        const scopedDraft = getScopedDraftPickSession(
            currentPickingContext?.sessionId,
            currentPickingContext?.channelId,
            currentPickingContext?.channelLabel
        );
        saveDraftPickSession({
            sessionId: currentPickingContext?.sessionId,
            channelId: currentPickingContext?.channelId,
            channelLabel: currentPickingContext?.channelLabel,
            channelColor: currentPickingContext?.channelColor,
            items: currentSessionItems,
            status: PICK_STATUS_DRAFT,
            operatorId: localStorage.getItem('currentUser'),
            createdAt: currentPickingContext?.createdAt || scopedDraft?.createdAt || getDataHoraBrasil(),
            executionId: currentPickingContext?.executionId || scopedDraft?.executionId || generateExecutionId(),
            isFastMode: getActivePickingFastMode(scopedDraft),
            modo_rapido: getActivePickingFastMode(scopedDraft),
            total_produtos_separados: countDifferentPickProducts(currentSessionItems),
            total_itens_separados: getPickItemsTotal(currentSessionItems),
            total_pacotes_montados: safeCount,
            totalPacotesMontados: safeCount,
            saveStatus: 'local_only'
        });
    }
    return safeCount;
}

function adjustPickPackageCount(delta) {
    syncPickPackageCount(getCurrentPickPackageCount() + Number(delta || 0), true);
    settlePickScannerInput(60);
}

function setPickPackageCount(value, persist = true, refocusScanner = false) {
    const nextCount = syncPickPackageCount(value, persist);
    if (refocusScanner) settlePickScannerInput(60);
    return nextCount;
}

function normalizeLocalPickDraft(draft = {}) {
    if (!draft || typeof draft !== 'object') return null;
    const sessionId = String(draft.sessionId || draft.separacao_id || draft.codigo_separacao || '').trim();
    if (!sessionId) return null;
    return {
        ...draft,
        sessionId,
        status: draft.status || PICK_STATUS_DRAFT,
        items: Array.isArray(draft.items) ? draft.items : [],
        timestamp: draft.timestamp || draft.atualizado_em || getDataHoraBrasil()
    };
}

function getLocalDraftPickSessionsMap() {
    try {
        const raw = JSON.parse(localStorage.getItem(PICK_DRAFT_SESSIONS_STORAGE_KEY) || '{}');
        const source = Array.isArray(raw)
            ? Object.fromEntries(raw.map(draft => [String(draft?.sessionId || ''), draft]).filter(([sessionId]) => sessionId))
            : (raw && typeof raw === 'object' ? raw : {});
        return Object.entries(source).reduce((acc, [sessionId, draft]) => {
            const normalized = normalizeLocalPickDraft({ ...(draft || {}), sessionId: draft?.sessionId || sessionId });
            if (normalized) acc[normalized.sessionId] = normalized;
            return acc;
        }, {});
    } catch (error) {
        console.warn('[PICKING] draft_pick_sessions invalido. Limpando lista local.', error);
        localStorage.removeItem(PICK_DRAFT_SESSIONS_STORAGE_KEY);
        return {};
    }
}

function setLocalDraftPickSessionsMap(map = {}) {
    const normalizedMap = Object.values(map || {}).reduce((acc, draft) => {
        const normalized = normalizeLocalPickDraft(draft);
        if (normalized) acc[normalized.sessionId] = normalized;
        return acc;
    }, {});
    localStorage.setItem(PICK_DRAFT_SESSIONS_STORAGE_KEY, JSON.stringify(normalizedMap));
    return normalizedMap;
}

function getLocalDraftPickSession(sessionId) {
    const targetSessionId = String(sessionId || '').trim();
    if (!targetSessionId) return null;
    return getLocalDraftPickSessionsMap()[targetSessionId] || null;
}

function getLocalDraftPickSessionsList() {
    return Object.values(getLocalDraftPickSessionsMap())
        .sort((a, b) => new Date(b.timestamp || b.createdAt || 0) - new Date(a.timestamp || a.createdAt || 0));
}

function upsertLocalDraftPickSession(draft) {
    const normalized = normalizeLocalPickDraft(draft);
    if (!normalized) return null;
    const map = getLocalDraftPickSessionsMap();
    map[normalized.sessionId] = normalized;
    setLocalDraftPickSessionsMap(map);
    return normalized;
}

function removeLocalDraftPickSession(sessionId) {
    const targetSessionId = String(sessionId || '').trim();
    if (!targetSessionId) return;
    const map = getLocalDraftPickSessionsMap();
    if (map[targetSessionId]) {
        delete map[targetSessionId];
        setLocalDraftPickSessionsMap(map);
    }
}

function getDraftPickSession() {
    try {
        const draft = JSON.parse(localStorage.getItem(PICK_CURRENT_DRAFT_STORAGE_KEY) || 'null');
        const normalized = normalizeLocalPickDraft(draft);
        if (normalized) {
            upsertLocalDraftPickSession(normalized);
            return normalized;
        }
        const currentSessionId = currentPickingContext?.sessionId || currentPickSession?.pickingData?.separacao_id || currentPickSession?.sessionId || '';
        return getLocalDraftPickSession(currentSessionId);
    } catch (error) {
        console.warn('[PICKING] draft_pick_session invalido. Limpando rascunho local.', error);
        localStorage.removeItem(PICK_CURRENT_DRAFT_STORAGE_KEY);
        return null;
    }
}

function saveDraftPickSession(draftPatch) {
    const patchSessionId = String(draftPatch?.sessionId || currentPickingContext?.sessionId || '').trim();
    const legacyDraft = getDraftPickSession();
    const existingDraft = patchSessionId
        ? (getLocalDraftPickSession(patchSessionId) || (String(legacyDraft?.sessionId || '') === patchSessionId ? legacyDraft : null))
        : legacyDraft;
    const draft = {
        ...(existingDraft || {}),
        ...(draftPatch || {}),
        timestamp: getDataHoraBrasil()
    };
    const normalized = normalizeLocalPickDraft(draft);
    if (!normalized) return draft;
    upsertLocalDraftPickSession(normalized);
    localStorage.setItem(PICK_CURRENT_DRAFT_STORAGE_KEY, JSON.stringify(normalized));
    return normalized;
}

function markDraftPickSaveStatus(status, error = null) {
    const draft = getDraftPickSession();
    if (!draft) return null;
    draft.saveStatus = status;
    draft.lastSaveAttemptAt = getDataHoraBrasil();
    if (error) draft.lastSaveError = error?.message || String(error);
    else delete draft.lastSaveError;
    return saveDraftPickSession(draft);
}

async function removeQueuedPickingDraftOperations(sessionId) {
    const targetSessionId = String(sessionId || '');
    if (!targetSessionId) return;

    const belongsToSession = (operation) => {
        if (!operation || operation.type !== 'supabase_pick_draft') return false;
        return String(operation.meta?.sessionId || '') === targetSessionId
            || String(operation.payload?.sessionId || '') === targetSessionId
            || String(operation.payload?.session?.separacao_id || '') === targetSessionId;
    };

    try {
        const db = await openOperationOutboxDB();
        await new Promise((resolve, reject) => {
            const tx = db.transaction(OPERATION_OUTBOX_STORE, 'readwrite');
            const store = tx.objectStore(OPERATION_OUTBOX_STORE);
            const request = store.getAll();
            request.onsuccess = () => {
                (request.result || [])
                    .filter(belongsToSession)
                    .forEach(operation => store.delete(operation.id));
            };
            request.onerror = () => reject(request.error);
            tx.oncomplete = resolve;
            tx.onerror = () => reject(tx.error);
        });
    } catch (error) {
        console.warn('[SEP] nao foi possivel limpar outbox do rascunho:', error);
    }

    try {
        const fallback = JSON.parse(localStorage.getItem('operation_outbox_fallback') || '[]');
        const filtered = fallback.filter(operation => !belongsToSession(operation));
        localStorage.setItem('operation_outbox_fallback', JSON.stringify(filtered));
    } catch (error) {
        console.warn('[SEP] nao foi possivel limpar fallback do outbox:', error);
    }

    await refreshOutboxPendingCount();
}

async function clearFinishedPickingDraftState(sessionId, options = {}) {
    const targetSessionId = String(sessionId || '');
    if (!targetSessionId) return;

    const draft = getDraftPickSession();
    removeLocalDraftPickSession(targetSessionId);
    if (!draft || String(draft.sessionId || '') === targetSessionId) {
        localStorage.removeItem(PICK_CURRENT_DRAFT_STORAGE_KEY);
    }

    if (!options.keepQueuedDraftOperations) {
        await removeQueuedPickingDraftOperations(targetSessionId);
    }

    if (currentPickingContext?.sessionId === targetSessionId) {
        currentPickingContext = null;
    }
    currentSessionItems = [];
    lastScannedPickItemKey = null;
    expandedPickItemKey = null;
    pickRemovalModeActive = false;
    lastPickScanAction = 'add';
    pickScanHistory = [];
}

async function discardPickingDraft(sessionId, options = {}) {
    const draft = getLocalDraftPickSession(sessionId) || getDraftPickSession();
    const targetSessionId = sessionId || draft?.sessionId || currentPickingContext?.sessionId;
    if (!targetSessionId) return true;

    let remoteRemoved = false;
    let remoteError = null;

    await removeQueuedPickingDraftOperations(targetSessionId);

    if (navigator.onLine && window.DataClient?.deletePickingDraftSupabase) {
        try {
            await window.DataClient.deletePickingDraftSupabase({ sessionId: targetSessionId });
            remoteRemoved = true;
        } catch (error) {
            remoteError = error;
            console.warn('[SEP] nao foi possivel excluir rascunho no servidor:', error);
        }
    }

    if (!draft || String(draft.sessionId || '') === String(targetSessionId)) {
        localStorage.removeItem(PICK_CURRENT_DRAFT_STORAGE_KEY);
    }
    removeLocalDraftPickSession(targetSessionId);

    currentSessionItems = [];
    lastScannedPickItemKey = null;
    expandedPickItemKey = null;
    pickRemovalModeActive = false;
    lastPickScanAction = 'add';
    pickScanHistory = [];
    if (currentPickingContext?.sessionId === targetSessionId) {
        currentPickingContext = null;
    }

    if (Array.isArray(appData.separacao)) {
        appData.separacao = appData.separacao.filter(row => String(row.separacao_id || row.id || '') !== String(targetSessionId));
    }
    if (Array.isArray(appData.separacao_itens)) {
        appData.separacao_itens = appData.separacao_itens.filter(row => String(row.separacao_id || '') !== String(targetSessionId));
    }

    if (!options.silent) {
        if (remoteError) {
            showToast("Rascunho removido deste aparelho. Nao foi possivel confirmar a exclusao no servidor.", "warning");
        } else if (remoteRemoved || !navigator.onLine) {
            showToast("Rascunho de separacao cancelado.");
        }
    }

    return !remoteError;
}

async function confirmDiscardPickingDraft(sessionId, channelId, channelLabel, channelColor) {
    const draft = getLocalDraftPickSession(sessionId) || getDraftPickSession();
    const targetSessionId = sessionId || draft?.sessionId || currentPickingContext?.sessionId;
    const hasItems = currentSessionItems.length > 0 || (draft?.items || []).length > 0;
    const itemLabel = hasItems ? 'Todos os produtos bipados nesse rascunho serao removidos.' : 'Nenhum produto foi bipado ainda.';

    const confirmed = await showAppConfirm({
        title: 'Cancelar rascunho de separação',
        message: `Cancelar o rascunho da separacao ${targetSessionId}?`,
        detail: `${itemLabel}\nUse isso quando iniciou a separacao no canal errado.`,
        confirmLabel: 'Cancelar rascunho',
        cancelLabel: 'Voltar',
        danger: true
    });
    if (!confirmed) return;

    await discardPickingDraft(targetSessionId);
    renderPickMenu();
}

function warnIfDraftPickWasNotSynced(draft) {
    if (!draft || !Array.isArray(draft.items) || draft.items.length === 0) return;
    if (draft.saveStatus === 'failed') {
        showToast("Rascunho local retomado, mas a ultima tentativa de salvar no servidor falhou.", "warning");
    } else if (draft.saveStatus === 'saving' || draft.saveStatus === 'local_only') {
        showToast("Rascunho local retomado. Nao foi confirmado o salvamento no servidor.", "warning");
    }
}

function getPickSessionChannelPrefix(channelLabel) {
    const normalized = normalizeOperationalLabel(channelLabel);
    if (normalized.includes('CORREIOS')) return 'CORREIOS';
    if (normalized.includes('FLEX')) return 'FLEX';
    if (normalized.includes('SHOPEE')) return 'SHOPEE';
    if (normalized.includes('MOTOBOY') || normalized.includes('MOTO')) return 'MOTOBOY';
    if (normalized.includes('TRANSPORTADORA')) return 'TRANSPORTADORA';
    if (normalized.includes('TURBO') || normalized.includes('ULTRA')) return 'TURBO';
    if (normalized.includes('OUTROS')) return 'OUTROS';
    return (normalized.split(' ')[0] || 'OUTROS').replace(/[^A-Z0-9]/g, '') || 'OUTROS';
}

function getPickSessionDateKey(date = new Date()) {
    return date.getDate().toString().padStart(2, '0') + (date.getMonth() + 1).toString().padStart(2, '0');
}

function getPickSessionSequenceFromId(sessionId, prefix, ddmm) {
    const match = String(sessionId || '').toUpperCase().match(new RegExp(`^SEP-${prefix}-${ddmm}-(\\d+)$`));
    return match ? Number(match[1] || 0) : 0;
}

async function refreshSeparacoesForPickSequence() {
    try {
        const data = await DataClient.loadModule('separacao', true);
        if (data) {
            appData.separacao = data.separacao || appData.separacao || [];
            appData.separacao_itens = data.separacao_itens || appData.separacao_itens || [];
        }
    } catch (error) {
        console.warn('[SEP] Falha ao atualizar separacoes para gerar ID. Usando cache local.', error);
    }
}

function generatePickSessionId(channelLabel) {
    const now = new Date();
    const ddmm = getPickSessionDateKey(now);
    const todayStr = formatDateBR(now);
    const cleanChannel = getPickSessionChannelPrefix(channelLabel);

    let maxSequence = 0;
    let legacyCount = 0;
    if (appData.separacao && Array.isArray(appData.separacao)) {
        appData.separacao.forEach(row => {
            const rowId = row.separacao_id || row.codigo_separacao || row.id || row.col_a || '';
            maxSequence = Math.max(maxSequence, getPickSessionSequenceFromId(rowId, cleanChannel, ddmm));
            const rowDate = row.data_separacao || row.col_d || row.col_D;
            const rowChannel = row.canal_nome || row.col_c || row.col_C;
            if (rowDate === todayStr && rowChannel === channelLabel) legacyCount += 1;
        });
    }
    getLocalDraftPickSessionsList().forEach(draft => {
        const rowId = draft.sessionId || draft.separacao_id || '';
        maxSequence = Math.max(maxSequence, getPickSessionSequenceFromId(rowId, cleanChannel, ddmm));
        const rowChannel = draft.channelLabel || draft.canal_nome || draft.canal || '';
        const rowDate = draft.createdAt || draft.timestamp || '';
        if (rowChannel === channelLabel && String(rowDate).includes(todayStr)) legacyCount += 1;
    });

    const seq = Math.max(maxSequence, legacyCount) + 1;
    return `SEP-${cleanChannel}-${ddmm}-${seq.toString().padStart(2, '0')}`;
}

function isTemporaryPickSessionId(sessionId) {
    return /^SEP-TEMP?-/.test(String(sessionId || '').trim().toUpperCase());
}

function isValidPickSessionId(sessionId) {
    return /^SEP-[A-Z0-9]+-\d{4}-\d{2,}$/.test(String(sessionId || '').trim().toUpperCase());
}

function getSafePickSessionId(sessionId, channelLabel) {
    const currentId = String(sessionId || '').trim();
    if (currentId && !isTemporaryPickSessionId(currentId) && isValidPickSessionId(currentId)) return currentId;
    return generatePickSessionId(channelLabel);
}

function assertValidPickSessionForPersist(sessionId, channelLabel, context = 'separacao') {
    const cleanSessionId = String(sessionId || '').trim();
    const cleanChannelLabel = String(channelLabel || '').trim();
    if (!cleanChannelLabel) {
        throw new Error(`Canal da separacao nao informado para ${context}. Volte e selecione o canal novamente.`);
    }
    if (!cleanSessionId) {
        throw new Error(`Codigo da separacao nao informado para ${context}.`);
    }
    if (isTemporaryPickSessionId(cleanSessionId) || !isValidPickSessionId(cleanSessionId)) {
        throw new Error(`Codigo de separacao invalido (${cleanSessionId}). Volte ao menu de Separacao e selecione o canal novamente.`);
    }
}

function buildPickingSessionPayload(sessionId, channelId, channelLabel, status = PICK_STATUS_DRAFT, createdAt = null) {
    assertValidPickSessionForPersist(sessionId, channelLabel, 'montar payload');
    const now = getDataHoraBrasil();
    const currentUser = localStorage.getItem('currentUser') || 'N/A';
    const stats = getPickingOperationalStats();
    const isFastMode = getActivePickingFastMode(getDraftPickSession());
    return {
        separacao_id: sessionId,
        pedido_referencia: '',
        canal_id: channelId || '',
        canal_nome: channelLabel || '',
        status,
        criado_por: currentUser,
        criado_em: createdAt || now,
        atualizado_em: now,
        total_produtos_separados: stats.total_produtos_separados,
        total_itens_separados: stats.total_itens_separados,
        total_pacotes_montados: stats.total_pacotes_montados,
        observacao: isFastMode ? PICK_FAST_OBSERVATION : PICK_MANUAL_OBSERVATION
    };
}

function getPickingScreenDataset() {
    const screen = document.querySelector('.pick-workflow-screen');
    return {
        sessionId: screen?.dataset.sessionId || '',
        channelId: screen?.dataset.channelId || '',
        channelLabel: screen?.dataset.channelLabel || '',
        channelColor: screen?.dataset.channelColor || '',
        createdAt: screen?.dataset.createdAt || ''
    };
}

async function ensureActivePickingContext() {
    if (currentPickingContext?.sessionId && !isTemporaryPickSessionId(currentPickingContext.sessionId) && currentPickingContext?.channelLabel) {
        return currentPickingContext;
    }

    const data = getPickingScreenDataset();
    if (data.sessionId && data.channelLabel && !isTemporaryPickSessionId(data.sessionId)) {
        currentPickingContext = {
            sessionId: data.sessionId,
            channelId: data.channelId,
            channelLabel: data.channelLabel,
            channelColor: data.channelColor || getChannelConfig(data.channelLabel).color || 'pdv',
            executionId: currentPickingContext?.executionId || generateExecutionId(),
            createdAt: data.createdAt || currentPickingContext?.createdAt || getDataHoraBrasil(),
            total_pacotes_montados: getCurrentPickPackageCount(data.sessionId, data.channelId, data.channelLabel),
            totalPacotesMontados: getCurrentPickPackageCount(data.sessionId, data.channelId, data.channelLabel)
        };
        return currentPickingContext;
    }

    if (data.channelLabel) {
        await refreshSeparacoesForPickSequence();
        const sessionId = generatePickSessionId(data.channelLabel);
        currentPickingContext = {
            sessionId,
            channelId: data.channelId || data.channelLabel,
            channelLabel: data.channelLabel,
            channelColor: data.channelColor || getChannelConfig(data.channelLabel).color || 'pdv',
            executionId: currentPickingContext?.executionId || generateExecutionId(),
            createdAt: data.createdAt || getDataHoraBrasil(),
            total_pacotes_montados: 0,
            totalPacotesMontados: 0
        };
        const screen = document.querySelector('.pick-workflow-screen');
        if (screen) screen.dataset.sessionId = sessionId;
        const sessionEl = document.getElementById('pick-session-id-label');
        if (sessionEl) sessionEl.textContent = sessionId;
        return currentPickingContext;
    }

    return null;
}

function buildPickingItemPayload(item) {
    const qty = Number(item?.qty || item?.qtd_separada || 1);
    return {
        id_interno: item?.id_interno || item?.col_a || item?.col_A || '',
        ean: item?.ean || '',
        descricao: item?.descricao_base || item?.descricao_completa || item?.col_aa || item?.descricao || '',
        qtd_solicitada: qty,
        qtd_separada: qty
    };
}

function getPickingProductId(item) {
    return normalizePickCode(item?.id_interno || item?.col_a || item?.col_A || '');
}

