function triggerScanSuccessGlow() {
    triggerScanFeedback('success');
    document.body.classList.remove('scan-success-glow');
    void document.body.offsetWidth;
    document.body.classList.add('scan-success-glow');

    clearTimeout(scanSuccessGlowTimeout);
    scanSuccessGlowTimeout = setTimeout(() => {
        document.body.classList.remove('scan-success-glow');
    }, 760);
}

function getPickItemTitle(item) {
    return item?.descricao_completa || item?.descricao_base || item?.descricao || item?.col_aa || 'PRODUTO';
}

function getPickItemMetaHTML(item) {
    const id = item?.id_interno || item?.col_a || item?.col_A || '-';
    const ean = item?.ean || '-';
    const sku = item?.sku_fornecedor || item?.sku || '-';
    return `
        <div>ID interno: ${id}</div>
        <div>EAN: ${ean}</div>
        <div>SKU: ${sku}</div>
    `;
}

async function persistPickingDraftItem(draft, item) {
    const sessionPayload = buildPickingSessionPayload(
        draft.sessionId,
        draft.channelId,
        draft.channelLabel,
        PICK_STATUS_DRAFT,
        draft.createdAt
    );
    const itemPayload = buildPickingItemPayload(item);
    const payload = {
        session: sessionPayload,
        item: itemPayload,
        executionId: draft.executionId || draft.sessionId
    };

    console.log('[SEP] produto bipado', {
        separacao_id: draft.sessionId,
        id_interno: itemPayload.id_interno,
        ean: itemPayload.ean,
        qtd_separada: itemPayload.qtd_separada
    });

    if (!navigator.onLine) {
        await queueOperation('supabase_pick_draft', payload, {
            module: 'separacao',
            sessionId: draft.sessionId,
            itemId: itemPayload.id_interno
        });
        return { queued: true };
    }

    try {
        return await withTimeout(
            DataClient.savePickingDraftSupabase(payload),
            15000,
            'salvar sessao de separacao'
        );
    } catch (error) {
        if (isRetryableConferenceSyncError(error)) {
            await queueOperation('supabase_pick_draft', payload, {
                module: 'separacao',
                sessionId: draft.sessionId,
                itemId: itemPayload.id_interno,
                lastOnlineError: error.message || String(error)
            });
            return { queued: true, error };
        }
        throw error;
    }
}

async function persistPickingDraftSession(draft) {
    if (!draft?.sessionId) return null;
    const sessionPayload = buildPickingSessionPayload(
        draft.sessionId,
        draft.channelId,
        draft.channelLabel,
        draft.status || PICK_STATUS_DRAFT,
        draft.createdAt
    );
    const payload = {
        session: sessionPayload,
        executionId: draft.executionId || draft.sessionId
    };

    if (!navigator.onLine) {
        await queueOperation('supabase_pick_draft', payload, {
            module: 'separacao',
            sessionId: draft.sessionId
        });
        return { queued: true };
    }

    try {
        return await withTimeout(
            DataClient.savePickingDraftSupabase(payload),
            15000,
            'salvar rascunho da separacao'
        );
    } catch (error) {
        if (isRetryableConferenceSyncError(error)) {
            await queueOperation('supabase_pick_draft', payload, {
                module: 'separacao',
                sessionId: draft.sessionId,
                lastOnlineError: error.message || String(error)
            });
            return { queued: true, error };
        }
        throw error;
    }
}

async function deletePickingDraftItemSupabaseDirect(payload = {}) {
    const client = window.supabaseClient;
    if (!client) throw new Error('Supabase client nao encontrado');

    const sessionId = payload.sessionId || payload.separacao_id;
    const idInterno = payload.idInterno || payload.id_interno;
    if (!sessionId) throw new Error('separacao_id nao informado');
    if (!idInterno) throw new Error('id_interno nao informado');

    const { error: itemError } = await client
        .from('separacao_itens')
        .delete()
        .eq('separacao_id', sessionId)
        .eq('id_interno', idInterno);

    if (itemError) throw itemError;

    const { error: sessionError } = await client
        .from('separacao')
        .update({ atualizado_em: getDataHoraBrasil() })
        .eq('separacao_id', sessionId);

    if (sessionError) throw sessionError;

    DataClient.invalidateCache('separacao');
    DataClient.invalidateCache('conferencia');

    return { deleted: true, sessionId, idInterno };
}

async function persistPickingFinal(sessionId) {
    const stats = getPickingOperationalStats(currentPickSession?.items || currentSessionItems);
    const payload = {
        sessionId,
        status: PICK_STATUS_READY_FOR_PACK,
        total_produtos_separados: stats.total_produtos_separados,
        total_itens_separados: stats.total_itens_separados,
        total_pacotes_montados: stats.total_pacotes_montados,
        executionId: generateExecutionId()
    };

    if (!navigator.onLine) {
        await queueOperation('supabase_pick_finalize', payload, {
            module: 'separacao',
            sessionId
        });
        return { queued: true };
    }

    try {
        return await withTimeout(
            DataClient.finalizePickingDraftSupabase(payload),
            20000,
            'finalizar separacao'
        );
    } catch (error) {
        if (isRetryableConferenceSyncError(error)) {
            await queueOperation('supabase_pick_finalize', payload, {
                module: 'separacao',
                sessionId,
                lastOnlineError: error.message || String(error)
            });
            return { queued: true, error };
        }
        throw error;
    }
}

async function startPickingSession(channelId, channelLabel, channelColor) {
    if (!String(channelLabel || '').trim()) {
        await showAppModal({
            type: 'error',
            title: 'Canal da separacao nao identificado',
            message: 'Escolha um canal antes de iniciar a separacao.',
            confirmText: 'Entendi'
        });
        return;
    }

    pickRemovalModeActive = false;
    lastPickScanAction = 'add';
    pickScanHistory = [];
    
    console.log('[SEP] canal selecionado', { channelId, channelLabel, channelColor });
    console.log(`[PICKING DEBUG] abriu nova bipagem sem retomar rascunho automaticamente`);
    await refreshSeparacoesForPickSequence();
    
    // Define contexto para criacao futura no primeiro item.
    currentPickingContext = {
        channelId, 
        channelLabel, 
        channelColor,
        sessionId: generatePickSessionId(channelLabel),
        executionId: generateExecutionId(),
        createdAt: getDataHoraBrasil(),
        isFastMode: isModoRapidoAtivo(),
        modo_rapido: isModoRapidoAtivo()
    };
    
    currentSessionItems = [];
    pickScanHistory = [];
    lastPickScanAction = 'add';
    renderPickingScreen(currentPickingContext.sessionId, channelId, channelLabel, channelColor);
}

function getPickOperatorInitials(name) {
    const parts = String(name || '').trim().split(/\s+/).filter(Boolean);
    if (parts.length === 0) return '--';
    if (parts.length === 1) return parts[0].slice(0, 2).toUpperCase();
    return `${parts[0][0] || ''}${parts[parts.length - 1][0] || ''}`.toUpperCase();
}

function getPickChannelSubtitle(channelLabel) {
    const label = String(channelLabel || '').toUpperCase();
    if (label.includes('FLEX')) return 'Flex Atacado';
    if (label.includes('MERCADO') || label.includes('ML')) return 'Marketplace';
    if (label.includes('SHOPEE') || label.includes('AGENCIA') || label.includes('AGÊNCIA')) return 'Agencia';
    if (label.includes('MAGALU') || label.includes('AMAZON')) return 'Marketplace';
    if (label.includes('PDV') || label.includes('BALC')) return 'Venda direta';
    return 'Canal operacional';
}

function formatPickCreatedAt(value) {
    return formatDateTimeBR(value || getDataHoraBrasil());
}

function getPickProductImage(item) {
    const rawUrl = item?.image_path || item?.url_imagem || item?.imagem || '';
    return rawUrl ? formatImageUrl(rawUrl) : '';
}

function getPickItemBrand(item) {
    return item?.marca || item?.brand || item?.fornecedor || 'SEM MARCA';
}

function getPickMainCode(item) {
    return item?.id_interno || item?.col_a || item?.col_A || item?.ean || item?.sku_fornecedor || item?.sku || '-';
}

function getPickItemSku(item) {
    return item?.sku_fornecedor || item?.sku || item?.codigo_sku || '-';
}

function getPickItemEan(item) {
    return item?.ean || item?.codigo_barras || item?.gtin || '-';
}

function getPickItemColor(item) {
    return item?.cor || item?.color || item?.colour || item?.col_h || item?.col_H || '-';
}

const HIGH_QTY_THRESHOLD = 15;

function getHighQtyThreshold() {
    const value = typeof getAppConfig === 'function' ? getAppConfig().quick_qty_after_beeps : HIGH_QTY_THRESHOLD;
    if (value === 'never') return Number.POSITIVE_INFINITY;
    const parsed = Number(value);
    return Number.isFinite(parsed) && parsed > 0 ? parsed : HIGH_QTY_THRESHOLD;
}

function getHighQtyProductInfo(item = {}) {
    const productId = item.id_interno || item.col_a || item.col_A || '';
    const product = productId
        ? (appData.products || []).find(p => String(p.id_interno || p.col_a || p.col_A || '') === String(productId))
        : null;
    const merged = { ...(product || {}), ...(item || {}) };
    return {
        title: getPickItemTitle(merged),
        sku: getPickItemSku(merged),
        ean: getPickItemEan(merged),
        color: getPickItemColor(merged),
        image: getPickProductImage(merged)
    };
}

function getManualQtyAuditPatch(previousQty, nextQty, reason) {
    return {
        ajuste_manual: true,
        quantidade_anterior: previousQty,
        quantidade_nova: nextQty,
        ajustado_por: localStorage.getItem('currentUser') || 'N/A',
        ajustado_em: getDataHoraBrasil(),
        motivo: reason
    };
}

function focusFlowScanInput(flow) {
    const inputId = flow === 'pack' ? 'pack-ean-input' : flow === 'inventory' ? 'inv-ean-input' : 'pick-ean-input';
    const input = document.getElementById(inputId);
    if (!input) return;
    input.value = '';
    setTimeout(() => input.focus(), 80);
}

function closeHighQtyModal() {
    document.getElementById('high-qty-modal')?.remove();
}

function openHighQtyModal({ item, currentQty, flow = 'pick', reason = 'quantidade_alta', operation = 'add', summaryLabel = 'Atual', directInput = false, onConfirm }) {
    return new Promise(resolve => {
        closeHighQtyModal();
        const info = getHighQtyProductInfo(item);
        const isRemove = operation === 'remove';
        const overlay = document.createElement('div');
        overlay.id = 'high-qty-modal';
        overlay.className = 'high-qty-modal-backdrop';

        const renderInputStep = (error = '') => {
            overlay.querySelector('.high-qty-card').innerHTML = `
                <button class="high-qty-close" type="button" aria-label="Fechar"><span class="material-symbols-rounded">close</span></button>
                <div class="high-qty-icon"><span class="material-symbols-rounded">edit_square</span></div>
                <h2>${isRemove ? 'INFORMAR QUANTIDADE PARA REMOVER' : 'INFORMAR QUANTIDADE TOTAL'}</h2>
                <p>${isRemove ? 'Digite a quantidade total que deve ser removida deste produto.' : 'Digite a quantidade final deste produto.'}</p>
                ${renderHighQtyProductSummary(info, currentQty, summaryLabel)}
                <label class="high-qty-input-label">
                    <span>${isRemove ? 'Quantidade para remover' : 'Quantidade total'}</span>
                    <input id="high-qty-input" type="number" inputmode="numeric" min="1" step="1" value="${Number(currentQty || 1)}">
                </label>
                ${error ? `<div class="high-qty-error">${escapeKitAttribute(error)}</div>` : ''}
                <div class="high-qty-actions">
                    <button type="button" class="high-qty-secondary" data-action="cancel">Cancelar</button>
                    <button type="button" class="high-qty-confirm" data-action="confirm">Confirmar quantidade</button>
                </div>
            `;
            bindInputStep();
            setTimeout(() => document.getElementById('high-qty-input')?.select(), 60);
        };

        const finish = (value = null) => {
            closeHighQtyModal();
            focusFlowScanInput(flow);
            resolve(value);
        };

        const bindInputStep = () => {
            overlay.querySelector('.high-qty-close')?.addEventListener('click', () => finish(null));
            overlay.querySelector('[data-action="cancel"]')?.addEventListener('click', () => finish(null));
            overlay.querySelector('[data-action="confirm"]')?.addEventListener('click', async () => {
                const input = document.getElementById('high-qty-input');
                const nextQty = Math.floor(Number(String(input?.value || '').replace(',', '.')));
                if (!Number.isFinite(nextQty) || nextQty < 1) {
                    renderInputStep('Informe uma quantidade válida.');
                    return;
                }
                const confirmedQty = await showAppConfirm({
                    title: isRemove ? 'Confirmar remoção' : 'Confirmar alteração',
                    message: isRemove ? `Confirmar remoção de ${nextQty} unidades?` : `Confirmar alteração para ${nextQty} unidades?`,
                    confirmLabel: 'Confirmar',
                    cancelLabel: 'Cancelar'
                });
                if (!confirmedQty) return;
                try {
                    await onConfirm?.(nextQty, reason);
                    finish(nextQty);
                } catch (error) {
                    console.error('[HIGH_QTY] erro ao confirmar quantidade:', error);
                    renderInputStep(error?.message || 'Erro ao confirmar quantidade.');
                }
            });
            overlay.querySelector('#high-qty-input')?.addEventListener('keydown', event => {
                if (event.key === 'Enter') {
                    event.preventDefault();
                    overlay.querySelector('[data-action="confirm"]')?.click();
                }
            });
        };

        overlay.innerHTML = `
            <div class="high-qty-card" role="dialog" aria-modal="true" aria-label="Quantidade alta detectada">
                <button class="high-qty-close" type="button" aria-label="Fechar"><span class="material-symbols-rounded">close</span></button>
                <div class="high-qty-icon"><span class="material-symbols-rounded">priority_high</span></div>
                <h2>QUANTIDADE ALTA DETECTADA</h2>
                <p>${isRemove ? `Você já bipou ${getHighQtyThreshold()} unidades para remover deste produto.` : `Você já bipou ${getHighQtyThreshold()} unidades deste produto.`}</p>
                ${renderHighQtyProductSummary(info, currentQty, summaryLabel)}
                <div class="high-qty-actions">
                    <button type="button" class="high-qty-secondary" data-action="continue">${isRemove ? 'Continuar removendo' : 'Continuar bipando'}</button>
                    <button type="button" class="high-qty-primary" data-action="input">${isRemove ? 'Informar quantidade para remover' : 'Informar quantidade total'}</button>
                </div>
            </div>
        `;
        document.body.appendChild(overlay);

        if (directInput) {
            renderInputStep();
            return;
        }

        overlay.querySelector('.high-qty-close')?.addEventListener('click', () => finish(null));
        overlay.querySelector('[data-action="continue"]')?.addEventListener('click', () => finish(null));
        overlay.querySelector('[data-action="input"]')?.addEventListener('click', () => renderInputStep());
    });
}

function renderHighQtyProductSummary(info, currentQty, summaryLabel = 'Atual') {
    return `
        <div class="high-qty-product">
            <div class="high-qty-image">
                ${info.image ? `<img src="${escapeKitAttribute(info.image)}" alt="${escapeKitAttribute(info.title)}" onerror="this.style.display='none'; this.parentElement.innerHTML='<span class=\\'material-symbols-rounded\\'>inventory_2</span>'">` : `<span class="material-symbols-rounded">inventory_2</span>`}
            </div>
            <div class="high-qty-copy">
                <strong>${escapeKitAttribute(info.title)}</strong>
                <span>SKU: ${escapeKitAttribute(info.sku)}</span>
                <span>EAN: ${escapeKitAttribute(info.ean)}</span>
                <span>COR: ${escapeKitAttribute(info.color)}</span>
            </div>
            <div class="high-qty-current">
                <span>${escapeKitAttribute(summaryLabel)}</span>
                <strong>${Number(currentQty || 0)}<small> un</small></strong>
            </div>
        </div>
    `;
}

function getPickItemStockInfoHTML(item) {
    const productId = getPickingProductId(item);
    if (!productId || !Array.isArray(appData.estoque)) {
        return `
            <div class="pick-product-stock is-empty" data-label="Estoque">
                <span>Estoque -</span>
                <small>sem saldo carregado</small>
            </div>
        `;
    }

    const stockEntries = appData.estoque.filter(entry => String(entry.id_interno || entry.col_a || entry.id || '') === String(productId));
    if (!stockEntries.length) {
        return `
            <div class="pick-product-stock is-empty" data-label="Estoque">
                <span>Estoque -</span>
                <small>sem local disponivel</small>
            </div>
        `;
    }

    const availableQty = calcularEstoqueDisponivel(stockEntries);
    const locations = stockEntries
        .map(entry => {
            const qty = parseStockQty(entry.saldo_total ?? entry.saldo ?? entry.saldo_disponivel);
            return {
                local: prettyLocal(entry.local || entry.col_b || ''),
                qty
            };
        })
        .filter(entry => entry.local && entry.qty > 0)
        .sort((a, b) => b.qty - a.qty)
        .slice(0, 2);

    const locationText = locations.length
        ? locations.map(entry => `${entry.local}: ${entry.qty}`).join(' / ')
        : 'sem local disponivel';

    return `
        <div class="pick-product-stock" data-label="Estoque">
            <span>Estoque ${availableQty}</span>
            <small>${escapeKitAttribute(locationText)}</small>
        </div>
    `;
}

