function showInputFeedback(inputId, type) {
    const input = document.getElementById(inputId);
    if (!input) return;
    
    const color = type === 'success' ? 'rgba(34, 197, 94, 0.4)' : 'rgba(239, 68, 68, 0.4)';
    const borderColor = type === 'success' ? '#22C55E' : '#EF4444';
    
    // Remove inline styles previously set if any
    input.style.transition = 'none';
    input.style.boxShadow = `0 0 0 4px ${color}`;
    input.style.borderColor = borderColor;
    
    // Force reflow
    void input.offsetWidth;
    
    input.style.transition = 'all 0.3s ease';
    input.style.boxShadow = '';
    input.style.borderColor = '';

    setTimeout(() => {
        if (input) {
            if (inputId === 'pick-ean-input') {
                preparePickScannerInput({ focus: true });
                if (isPickMobileViewport()) input.blur();
            } else {
                input.focus();
            }
            console.log(`[BIP CONTINUO DEBUG] input limpo e foco restaurado no ${inputId}`);
        }
    }, 300);
}

function normalizePickCode(rawValue) {
    return String(rawValue || '').trim().replace(/\s+/g, '');
}

function getPickScanInputPlaceholder() {
    return pickRemovalModeActive
        ? 'Bipe o produto para remover 1 unidade'
        : 'Bipe o produto (EAN, SKU ou código interno)';
}

function updatePickRemovalModeUI() {
    const screen = document.querySelector('.pick-workflow-screen');
    const input = document.getElementById('pick-ean-input');
    const button = document.getElementById('pick-remove-scan-toggle');
    const label = document.getElementById('pick-remove-scan-label');
    const badge = document.getElementById('pick-removal-badge');

    screen?.classList.toggle('pick-removal-active', pickRemovalModeActive);
    if (input) input.placeholder = getPickScanInputPlaceholder();
    if (button) button.classList.toggle('is-active', pickRemovalModeActive);
    if (label) label.textContent = pickRemovalModeActive ? 'Cancelar remoção' : 'Remover por bipagem';
    badge?.classList.toggle('hidden', !pickRemovalModeActive);
}

function setPickRemovalMode(active) {
    pickRemovalModeActive = Boolean(active);
    updatePickRemovalModeUI();
    settlePickScannerInput(60);
}

function togglePickRemovalMode() {
    setPickRemovalMode(!pickRemovalModeActive);
}

function pickItemMatchesCode(item, cleanCode) {
    const code = normalizePickCode(cleanCode);
    if (!code) return false;
    const possibleCodes = [
        getPickingProductId(item),
        item?.id_interno,
        item?.col_a,
        item?.col_A,
        item?.ean,
        item?.codigo_barras,
        item?.sku_fornecedor,
        item?.sku
    ];
    return possibleCodes.some(value => normalizePickCode(value) === code);
}

function addPickScanHistory(action, itemOrText) {
    pickScanHistory = [];
}

function renderPickScanHistory() {
    const container = document.getElementById('pick-scan-history');
    if (!container) return;
    if (!pickScanHistory.length) {
        container.classList.add('hidden');
        container.innerHTML = '';
        return;
    }

    container.classList.remove('hidden');
    container.innerHTML = pickScanHistory.map(entry => `
        <span class="${entry.action === 'remove' ? 'is-remove' : 'is-add'}">
            <strong>${entry.action === 'remove' ? '-' : '+'}</strong>
            ${escapeKitAttribute(entry.label)}
        </span>
    `).join('');
}

function findProductInLocalCacheByCode(cleanCode) {
    console.log('[SEP] buscando cache', cleanCode);
    const code = normalizePickCode(cleanCode);
    const product = (appData.products || []).find(p =>
        (normalizePickCode(p.ean) && normalizePickCode(p.ean) === code) ||
        (getPickingProductId(p) && getPickingProductId(p) === code) ||
        (normalizePickCode(p.sku_fornecedor || p.sku) && normalizePickCode(p.sku_fornecedor || p.sku) === code)
    );

    if (product) {
        console.log('[SEP] produto encontrado cache', {
            id_interno: product.id_interno || product.col_a || product.col_A || '',
            ean: product.ean || '',
            sku_fornecedor: product.sku_fornecedor || product.sku || ''
        });
    }

    return product || null;
}

function upsertProductIntoLocalCache(product) {
    if (!product) return null;
    const indexed = hydrateProdutosForSearch([product])[0];
    if (!indexed) return null;

    if (!Array.isArray(appData.products)) appData.products = [];
    const indexedId = getPickingProductId(indexed);
    const idx = indexedId ? appData.products.findIndex(p => getPickingProductId(p) === indexedId) : -1;

    if (idx >= 0) appData.products[idx] = { ...appData.products[idx], ...indexed };
    else appData.products.unshift(indexed);

    console.log('[SEP] total produtos carregados', appData.products.length);
    return indexed;
}

async function findProductForPicking(cleanCode) {
    let product = findProductInLocalCacheByCode(cleanCode);
    if (product) return product;

    try {
        const supabaseProduct = await DataClient.findProdutoByCodeSupabase(cleanCode);
        if (supabaseProduct) return upsertProductIntoLocalCache(supabaseProduct);
    } catch (error) {
        console.warn('[SEP] refresh supabase erro', {
            message: error?.message,
            details: error?.details,
            hint: error?.hint,
            code: error?.code,
            value: cleanCode
        });
    }

    console.log('[SEP] produto nao encontrado', cleanCode);
    return null;
}

function getCurrentPickDraftForUpdate(saveStatus = 'saving') {
    const contextSessionId = currentPickingContext?.sessionId;
    const existingDraft = getScopedDraftPickSession(
        contextSessionId,
        currentPickingContext?.channelId,
        currentPickingContext?.channelLabel
    ) || {};
    const draftSessionId = existingDraft.sessionId;
    const channelLabel = currentPickingContext?.channelLabel || existingDraft.channelLabel || '';
    const sessionId = !isTemporaryPickSessionId(contextSessionId) && contextSessionId
        ? contextSessionId
        : (!isTemporaryPickSessionId(draftSessionId) && draftSessionId ? draftSessionId : getSafePickSessionId('', channelLabel));
    const packageCount = getCurrentPickPackageCount();
    const stats = getPickingOperationalStats(currentSessionItems);
    return saveDraftPickSession({
        sessionId,
        channelId: currentPickingContext?.channelId || existingDraft.channelId || '',
        channelLabel: channelLabel || 'OUTROS',
        channelColor: currentPickingContext?.channelColor || existingDraft.channelColor || 'pdv',
        items: currentSessionItems,
        status: PICK_STATUS_DRAFT,
        isFastMode: getActivePickingFastMode(existingDraft),
        modo_rapido: getActivePickingFastMode(existingDraft),
        operatorId: localStorage.getItem('currentUser'),
        createdAt: existingDraft.createdAt || currentPickingContext?.createdAt || getDataHoraBrasil(),
        executionId: existingDraft.executionId || currentPickingContext?.executionId || generateExecutionId(),
        total_produtos_separados: stats.total_produtos_separados,
        total_itens_separados: stats.total_itens_separados,
        total_pacotes_montados: packageCount,
        totalPacotesMontados: packageCount,
        saveStatus,
        lastSaveAttemptAt: getDataHoraBrasil()
    });
}

async function persistPickingItemRemoval(draft, removedItem, removedAll) {
    if (!removedItem) return null;
    if (!removedAll) {
        const persistResult = await persistPickingDraftItem(draft, removedItem);
        markDraftPickSaveStatus(persistResult?.queued ? 'queued' : 'synced');
        return persistResult;
    }

    const payload = {
        sessionId: draft.sessionId,
        idInterno: removedItem.id_interno || removedItem.col_a || removedItem.col_A || getPickingProductId(removedItem),
        executionId: draft.executionId || draft.sessionId
    };

    if (!payload.sessionId || !payload.idInterno) return null;

    if (!navigator.onLine) {
        await queueOperation('supabase_pick_draft_item_delete', payload, {
            module: 'separacao',
            sessionId: payload.sessionId,
            itemId: payload.idInterno
        });
        markDraftPickSaveStatus('queued');
        return { queued: true };
    }

    const result = await deletePickingDraftItemSupabaseDirect(payload);
    markDraftPickSaveStatus('synced');
    return result;
}

async function removePickItemByScan(cleanCode, input) {
    const existingIndex = currentSessionItems.findIndex(item => pickItemMatchesCode(item, cleanCode));

    if (existingIndex < 0) {
        playBeep('error');
        showScanFeedback('warning', 'Produto não está nesta separação');
        showToast('Produto não está nesta separação', 'warning');
        if (input) input.value = '';
        updatePickRemovalModeUI();
        showInputFeedback('pick-ean-input', 'error');
        return;
    }

    const item = currentSessionItems[existingIndex];
    const productKey = getPickingProductId(item);
    const currentQty = Number(item.qty) || Number(item.qtd_separada) || 1;
    if (!item.remove_scan_count) item.remove_scan_origin_qty = currentQty;
    const nextQty = Math.max(0, currentQty - 1);
    let removedAll = nextQty <= 0;
    let removedFeedbackQty = 1;

    playBeep('success');
    lastScannedPickItemKey = productKey;
    lastPickScanAction = 'remove';
    expandedPickItemKey = null;

    currentSessionItems.splice(existingIndex, 1);
    if (!removedAll) {
        item.qty = nextQty;
        item.remove_scan_count = Number(item.remove_scan_count || 0) + 1;
        item.scanTime = formatTimeBR();
        item.lastRemovedAt = Date.now();
        item.lastAddedAt = 0;
        currentSessionItems.unshift(item);
    }

    if (!removedAll && Number(item.remove_scan_count || 0) === getHighQtyThreshold() && !item.high_remove_qty_prompted) {
        item.high_remove_qty_prompted = true;
        await openHighQtyModal({
            item,
            currentQty: item.remove_scan_count,
            flow: 'pick',
            reason: 'quantidade_alta',
            operation: 'remove',
            summaryLabel: 'Removidas por bipagem',
            onConfirm: async (totalToRemove, reason) => {
                const removedByScan = Number(item.remove_scan_count || 0);
                const originQty = Number(item.remove_scan_origin_qty || (Number(item.qty || 0) + removedByScan));
                if (totalToRemove < removedByScan) {
                    throw new Error(`Informe uma quantidade igual ou maior que ${removedByScan}.`);
                }
                const finalQty = Math.max(0, originQty - totalToRemove);
                Object.assign(item, getManualQtyAuditPatch(originQty, finalQty, reason));
                item.qty = finalQty;
                item.remove_scan_count = totalToRemove;
                removedFeedbackQty = Math.min(totalToRemove, originQty);
                item.scanTime = formatTimeBR();
                item.lastRemovedAt = Date.now();
                lastScannedPickItemKey = productKey;
                lastPickScanAction = 'remove';
                const currentIndex = currentSessionItems.indexOf(item);
                if (currentIndex >= 0) currentSessionItems.splice(currentIndex, 1);
                if (finalQty > 0) currentSessionItems.unshift(item);
                updatePickItemsList();
                showToast(finalQty > 0 ? 'Quantidade removida atualizada.' : 'Produto removido da separação', 'success');
            }
        });
        removedAll = !currentSessionItems.includes(item) || Number(item.qty || 0) <= 0;
    }

    const draft = getCurrentPickDraftForUpdate('saving');
    if (currentPackSession) {
        currentPackSession.items = currentSessionItems;
        localStorage.setItem('draft_pack_session', JSON.stringify(currentPackSession));
    }
    addPickScanHistory('remove', item);
    updatePickItemsList();
    if (input) input.value = '';

    try {
        const result = await persistPickingItemRemoval(draft, item, removedAll);
        if (result?.queued) showToast('Remoção salva localmente para sincronizar.');
        else showToast(removedAll ? 'Produto removido da separação' : `${removedFeedbackQty} ${removedFeedbackQty === 1 ? 'unidade removida' : 'unidades removidas'}`);
        showPickRemovalFeedbackToast(item, removedFeedbackQty);
    } catch (error) {
        markDraftPickSaveStatus('failed', error);
        console.error('[SEP] erro ao remover item por bipagem', error);
        showScanFeedback('error', 'Erro ao salvar remoção');
        showToast(`Erro ao salvar remoção: ${error?.message || error}`, 'error');
    }

    setPickRemovalMode(false);
    showInputFeedback('pick-ean-input', 'success');
}

async function addPickItem(scannedEan = null) {
    const activeContext = await ensureActivePickingContext();
    if (!activeContext?.sessionId || !activeContext?.channelLabel || isTemporaryPickSessionId(activeContext.sessionId)) {
        showScanFeedback('error', 'Canal da separação inválido');
        await showAppModal({
            type: 'error',
            title: 'Canal da separação não identificado',
            message: 'Volte para o menu de Separação e escolha o canal novamente antes de bipar.',
            confirmText: 'Entendi'
        });
        return;
    }

    const input = document.getElementById('pick-ean-input');
    const rawCode = (scannedEan ?? input?.value ?? '').toString();
    const ean = normalizePickCode(rawCode);
    console.log('[SEP] codigo bruto', rawCode);
    console.log('[SEP] codigo normalizado', ean);
    if (!ean) {
        showScanFeedback('error', 'Código inválido');
        return;
    }

    if (pickRemovalModeActive) {
        await removePickItemByScan(ean, input);
        return;
    }

    const product = await findProductForPicking(ean);

    if (product) {
        const productId = getPickingProductId(product);
        if (!productId) {
            showScanFeedback('error', 'Produto sem ID interno');
            showToast(`PRODUTO SEM ID INTERNO: ${ean}`);
            input.value = '';
            showInputFeedback('pick-ean-input', 'error');
            return;
        }

        const allowNegative = isSaidaEstoqueZeroPermitida();
        const stock = getPickAvailableStock(productId);
        const existingItemForQty = currentSessionItems.find(item => getPickingProductId(item) === productId);
        const currentDraftQty = existingItemForQty ? existingItemForQty.qty : 0;

        if (stock < (currentDraftQty + 1)) {
            console.log('[SEPARACAO_ESTOQUE_NEGATIVO] validacao bipagem', {
                permitir_estoque_negativo: allowNegative,
                produto: productId,
                descricao: getPickItemTitle(product),
                estoque_atual: stock,
                quantidade_solicitada: currentDraftQty + 1,
                faltante: (currentDraftQty + 1) - stock,
                ponto: 'bipagem',
                decisao: allowNegative ? 'permitiu_com_alerta' : 'bloqueou'
            });
            if (!allowNegative) {
                showScanFeedback('error', 'Estoque insuficiente');
                await showAppModal({
                    type: 'error',
                    title: 'Estoque insuficiente',
                    message: 'Estoque insuficiente para finalizar a separação. Ative “Permitir estoque negativo” em Configurações ou ajuste a quantidade.',
                    detail: `${getPickItemTitle(product)}: disponível ${stock}, solicitado ${currentDraftQty + 1}.`,
                    confirmText: 'Entendi'
                });
                input.value = '';
                showInputFeedback('pick-ean-input', 'error');
                return;
            } else {
                if (!window.pickNegativeStockWarnings) window.pickNegativeStockWarnings = new Set();
                const warningKey = `${currentPickSession?.id || currentPickSession?.channelId || 'pick'}:${product.id_interno || product.ean || ean}`;
                if (!window.pickNegativeStockWarnings.has(warningKey)) {
                    window.pickNegativeStockWarnings.add(warningKey);
                    showToast(`Estoque insuficiente, mas permitido: ${getPickItemTitle(product)}`);
                }
            }
        }

        playBeep('success');
        console.log('[SEP] produto bipado', {
            ean,
            id_interno: product.id_interno || product.col_a || product.col_A || '',
            descricao: getPickItemTitle(product)
        });

        const existingIndex = currentSessionItems.findIndex(item => getPickingProductId(item) === productId);
        if (existingIndex >= 0) {
            const existingItem = currentSessionItems[existingIndex];
            existingItem.qty = (existingItem.qty || 1) + 1;
            existingItem.scanTime = formatTimeBR();
            existingItem.lastAddedAt = Date.now();
            currentSessionItems.splice(existingIndex, 1);
            currentSessionItems.unshift(existingItem);
        } else {
            currentSessionItems.unshift({
                ...product,
                qty: 1,
                scanTime: formatTimeBR(),
                lastAddedAt: Date.now()
            });
        }
        lastScannedPickItemKey = productId;
        lastPickScanAction = 'add';
        expandedPickItemKey = null;
        addPickScanHistory('add', currentSessionItems[0] || product);
        const scannedPickItem = currentSessionItems[0];

        if ((Number(scannedPickItem?.qty || 0) === getHighQtyThreshold()) && !scannedPickItem.high_qty_prompted) {
            scannedPickItem.high_qty_prompted = true;
            await openHighQtyModal({
                item: scannedPickItem,
                currentQty: scannedPickItem.qty,
                flow: 'pick',
                reason: 'quantidade_alta',
                onConfirm: async (nextQty, reason) => {
                    const previousQty = Number(scannedPickItem.qty || 0);
                    Object.assign(scannedPickItem, getManualQtyAuditPatch(previousQty, nextQty, reason));
                    scannedPickItem.qty = nextQty;
                    scannedPickItem.scanTime = formatTimeBR();
                    scannedPickItem.lastAddedAt = Date.now();
                    lastScannedPickItemKey = productId;
                    lastPickScanAction = 'add';
                    updatePickItemsList();
                    showToast('Quantidade atualizada.', 'success');
                }
            });
        }

        const scopedDraft = getScopedDraftPickSession(
            currentPickingContext?.sessionId,
            currentPickingContext?.channelId,
            currentPickingContext?.channelLabel
        );
        let draft;
        
        if (!scopedDraft) {
            console.log(`[PICKING DEBUG] primeiro item bipado, criando rascunho`);
            const now = new Date();
            draft = {
                sessionId: activeContext.sessionId,
                channelId: activeContext.channelId || '',
                channelLabel: activeContext.channelLabel,
                channelColor: activeContext.channelColor || 'pdv',
                items: [],
                operatorId: localStorage.getItem('currentUser'),
                status: PICK_STATUS_DRAFT,
                timestamp: getDataHoraBrasil(now),
                createdAt: currentPickingContext?.createdAt || getDataHoraBrasil(now),
                executionId: currentPickingContext?.executionId || generateExecutionId(),
                isFastMode: getActivePickingFastMode(),
                modo_rapido: getActivePickingFastMode(),
                total_produtos_separados: 0,
                total_itens_separados: 0,
                total_pacotes_montados: getCurrentPickPackageCount(),
                totalPacotesMontados: getCurrentPickPackageCount()
            };
        } else {
            draft = scopedDraft;
        }

        draft.sessionId = getSafePickSessionId(currentPickingContext?.sessionId || draft.sessionId, currentPickingContext?.channelLabel || draft.channelLabel);
        draft.channelId = currentPickingContext?.channelId || draft.channelId;
        draft.channelLabel = currentPickingContext?.channelLabel || draft.channelLabel;
        draft.channelColor = currentPickingContext?.channelColor || draft.channelColor;
        draft.items = currentSessionItems;
        draft.status = PICK_STATUS_DRAFT;
        draft.isFastMode = getActivePickingFastMode(draft);
        draft.modo_rapido = getActivePickingFastMode(draft);
        draft.timestamp = getDataHoraBrasil();
        draft.createdAt = draft.createdAt || getDataHoraBrasil();
        draft.executionId = draft.executionId || currentPickingContext?.executionId || generateExecutionId();
        const draftStats = getPickingOperationalStats(currentSessionItems);
        draft.total_produtos_separados = draftStats.total_produtos_separados;
        draft.total_itens_separados = draftStats.total_itens_separados;
        draft.total_pacotes_montados = getCurrentPickPackageCount();
        draft.totalPacotesMontados = getCurrentPickPackageCount();
        draft.saveStatus = 'saving';
        draft.lastSaveAttemptAt = getDataHoraBrasil();
        draft = saveDraftPickSession(draft);

        let pickPersistFailed = false;
        try {
            const itemToPersist = currentSessionItems.find(item => getPickingProductId(item) === productId) || product;
            const persistResult = await persistPickingDraftItem(draft, itemToPersist);
            markDraftPickSaveStatus(persistResult?.queued ? 'queued' : 'synced');
            if (persistResult?.queued) {
                showToast("Item salvo localmente para sincronizar.");
            }
        } catch (error) {
            pickPersistFailed = true;
            markDraftPickSaveStatus('failed', error);
            console.error('[SEP] erro ao salvar item', {
                message: error?.message,
                details: error?.details,
                hint: error?.hint,
                code: error?.code
            });
            showScanFeedback('error', 'Erro ao salvar item');
            showToast(`Erro ao salvar item: ${error?.message || error}`, "error");
        }

        if (!pickPersistFailed) {
            showPickScanCenterToast(currentSessionItems.find(item => getPickingProductId(item) === productId) || product);
            triggerScanSuccessGlow();
        }
        if (currentPackSession) {
            currentPackSession.items = currentSessionItems;
            localStorage.setItem('draft_pack_session', JSON.stringify(currentPackSession));
        }
    } else {
        showScanFeedback('warning', 'Produto não cadastrado');
        await showAppModal({
            type: 'warning',
            title: 'Produto não encontrado',
            message: `Produto não cadastrado para o código ${ean}.`,
            confirmText: 'OK'
        });
    }

    input.value = '';
    updatePickItemsList();
    showInputFeedback('pick-ean-input', product ? 'success' : 'error');
}

function updatePickItemsList() {
    const container = document.getElementById('pick-items-list');
    const countEl = document.getElementById('pick-list-count');
    updatePickSummaryUI();
    const differentProducts = countDifferentPickProducts(currentSessionItems);
    if (countEl) countEl.textContent = `${differentProducts} ${differentProducts === 1 ? 'PRODUTO' : 'PRODUTOS'}`;
    if (!container) return;
    
    if (currentSessionItems.length === 0) {
        container.innerHTML = `
            <div class="pick-empty-state">
                <span class="material-symbols-rounded">barcode_scanner</span>
                <strong>Nenhum produto bipado</strong>
                <small>Use o campo acima para iniciar a separacao.</small>
            </div>
        `;
        return;
    }

    container.innerHTML = currentSessionItems.map((item, index) => {
        const productKey = getPickingProductId(item) || `pick-item-${index}`;
        const isLastScanned = productKey === lastScannedPickItemKey;
        const isLastRemoval = isLastScanned && lastPickScanAction === 'remove';
        const isExpanded = productKey === expandedPickItemKey;
        const addedRecently = Date.now() - Number(item.lastAddedAt || 0) < 4500;
        const removedRecently = Date.now() - Number(item.lastRemovedAt || 0) < 4500;
        return `
        <article class="pick-product-row separacao-item-card fade-in ${isLastScanned ? 'is-last-scanned' : ''} ${isLastRemoval ? 'is-last-removed' : ''} ${addedRecently ? 'recently-added' : ''} ${removedRecently ? 'recently-removed' : ''}">
            <div class="pick-product-main" data-label="Produto">
                <div class="pick-product-image">
                    ${getPickProductImage(item) ? `<img src="${escapeKitAttribute(getPickProductImage(item))}" alt="${escapeKitAttribute(getPickItemTitle(item))}" onerror="this.style.display='none'; this.parentElement.innerHTML='<span class=\\'material-symbols-rounded\\'>inventory_2</span>'">` : `<span class="material-symbols-rounded">inventory_2</span>`}
                </div>
                <div>
                    <strong>${escapeKitAttribute(getPickItemTitle(item))}</strong>
                    <div class="pick-product-meta">
                        <span>SKU: ${escapeKitAttribute(getPickItemSku(item))}</span>
                        <span>EAN: ${escapeKitAttribute(getPickItemEan(item))}</span>
                        <span>COR: ${escapeKitAttribute(getPickItemColor(item))}</span>
                    </div>
                </div>
            </div>
            <div class="pick-product-qty" data-label="Quantidade bipada">
                <span class="pick-qty-number">${Number(item.qty) || 0}</span>
                <span class="pick-qty-unit">un</span>
            </div>
            <button class="pick-product-delete" onclick="event.stopPropagation(); removePickItem(${index})" type="button" aria-label="Remover item">
                <span class="material-symbols-rounded">delete</span>
            </button>
            ${isLastScanned ? `
                <div class="pick-added-now ${isLastRemoval ? 'is-remove' : ''}">
                    <span class="material-symbols-rounded">${isLastRemoval ? 'remove_done' : 'check'}</span>
                    ${isLastRemoval ? '1 unidade removida' : 'Adicionado agora'}
                </div>
            ` : ''}
        </article>
    `}).join('');
}

function togglePickItemExpanded(productKey) {
    expandedPickItemKey = expandedPickItemKey === productKey ? null : productKey;
    updatePickItemsList();
}

function removePickItem(index) {
    const removedItem = currentSessionItems[index];
    const removedKey = getPickingProductId(removedItem) || `pick-item-${index}`;
    currentSessionItems.splice(index, 1);
    if (lastScannedPickItemKey === removedKey) lastScannedPickItemKey = null;
    if (expandedPickItemKey === removedKey) expandedPickItemKey = null;
    updatePickItemsList();
    if (currentSessionItems.length === 0) {
        discardPickingDraft(currentPickingContext?.sessionId, { silent: true })
            .catch(error => console.warn('[SEP] nao foi possivel cancelar rascunho vazio:', error));
    } else {
        saveDraftPickSession({
            items: currentSessionItems,
            total_pacotes_montados: getCurrentPickPackageCount(),
            totalPacotesMontados: getCurrentPickPackageCount(),
            saveStatus: 'local_only'
        });
    }
    settlePickScannerInput(80);
}

async function pausePickingSession(sessionId, channelId, channelLabel, channelColor) {
    const draft = saveDraftPickSession({
        sessionId,
        channelId,
        channelLabel,
        channelColor,
        items: currentSessionItems,
        status: PICK_STATUS_DRAFT,
        operatorId: localStorage.getItem('currentUser'),
        createdAt: currentPickingContext?.createdAt || getDataHoraBrasil(),
        executionId: currentPickingContext?.executionId || generateExecutionId(),
        total_pacotes_montados: getCurrentPickPackageCount(),
        totalPacotesMontados: getCurrentPickPackageCount(),
        saveStatus: 'saving'
    });

    try {
        const result = await persistPickingDraftSession(draft);
        markDraftPickSaveStatus(result?.queued ? 'queued' : 'synced');
        showToast(result?.queued ? "Separacao pausada localmente para sincronizar." : "Separacao pausada.");
    } catch (error) {
        markDraftPickSaveStatus('failed', error);
        showToast("Separacao pausada localmente. Sincronizacao pendente.", "warning");
    }

    renderPickMenu();
}


async function finishPickingSession(sessionId, channelId, channelLabel, channelColor) {
    if (isFinalizing) return;
    isFinalizing = true;

    const submitBtn = document.querySelector(`button[onclick^="finishPickingSession"]`);
    if (submitBtn) { submitBtn.disabled = true; submitBtn.innerHTML = 'Salvando...'; }

    try {
        if (currentSessionItems.length === 0) {
            await showAppModal({
                type: 'warning',
                title: 'Separação vazia',
                message: 'Adicione pelo menos um item para finalizar.',
                confirmText: 'OK'
            });
            return;
        }

        const currentUser = localStorage.getItem('currentUser');
        const now = getDataHoraBrasil();
        const activeDraft = getScopedDraftPickSession(sessionId, channelId, channelLabel);
        const modoRapidoAtivo = isModoRapidoAtivo() || getActivePickingFastMode(activeDraft);
        const stats = getPickingOperationalStats(currentSessionItems);

        const pickingData = {
            separacao_id: sessionId,
            canal_id: channelId,
            canal_nome: channelLabel,
            data_separacao: formatDateBR(getDataBrasilISO()),
            status: 'em_separacao',
            criado_por: currentUser,
            criado_em: now,
            finalizado_em: now,
            data_hora: now,
            origem_operacional: 'manual_nf',
            pedido_origem_id: '',
            marketplace_order_id: '',
            total_produtos_separados: stats.total_produtos_separados,
            total_itens_separados: stats.total_itens_separados,
            total_pacotes_montados: stats.total_pacotes_montados,
            observacao: modoRapidoAtivo ? PICK_FAST_OBSERVATION : 'SEPARACAO MANUAL POR NF',
            isFastMode: modoRapidoAtivo,
            modo_rapido: modoRapidoAtivo
        };

        const groupedItems = currentSessionItems.reduce((acc, item) => {
            const key = getPickingProductId(item) || 'unknown';
            if (!acc[key]) acc[key] = { ...item, qty: 0 };
            acc[key].qty += (item.qty || 1);
            return acc;
        }, {});

        const conferenceRows = Object.values(groupedItems).map(item => ({
            separacao_id: sessionId,
            id_interno: item.id_interno || '',
            ean: item.ean,
            descricao: item.descricao_base,
            qtd_separada: item.qty,
            qtd_conferida: modoRapidoAtivo ? item.qty : 0,
            divergencia: modoRapidoAtivo ? 'OK' : 'FALTA',
            conferido_por: modoRapidoAtivo ? currentUser : '',
            conferido_em: modoRapidoAtivo ? now : '',
            processed: false
        }));

        const session = {
            id: sessionId,
            channel: channelLabel,
            channelColor: channelColor,
            items: currentSessionItems,
            user: currentUser,
            time: now,
            pickingData,
            conferenceRows,
            isFastMode: modoRapidoAtivo,
            modo_rapido: modoRapidoAtivo,
            total_produtos_separados: stats.total_produtos_separados,
            total_itens_separados: stats.total_itens_separados,
            total_pacotes_montados: stats.total_pacotes_montados
        };

        currentPickSession = session;
        isFinalizing = false;
        await savePickResultFinal(sessionId, channelId, channelLabel, channelColor);


    } catch (error) {
        console.error('[SEPARACAO] erro ao finalizar', error);
        await showAppModal({
            type: 'error',
            title: 'Erro ao processar separação',
            message: error?.message || 'Erro ao processar separação.',
            confirmText: 'Entendi'
        });
    } finally {
        isFinalizing = false;
        const submitBtn = document.querySelector(`button[onclick^="finishPickingSession"]`);
        if (submitBtn) { submitBtn.disabled = false; submitBtn.innerHTML = 'FINALIZAR SEPARACAO'; }
    }
}

