        pedido: '',
        cpf_cnpj: '',
        telefone: '',
        email: '',
        cep: '',
        rua: '',
        numero: '',
        complemento: '',
        bairro: '',
        cidade: '',
        estado: '',
        referencia: '',
        endereco_completo: '',
        tipo_envio: '',
        transportadora: '',
        codigo_rastreio: '',
        data_execucao: '',
        data_postagem: '',
        data_envio_cliente: '',
        status_postagem: 'Aguardando postagem',
